(1, 'a0d999b205c7', NULL, 'Confirm your subscription to [site:title]', 'confirmation_email', '', '', 'draft', '', '', '', '{\"content\":{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"vertical\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"horizontal\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"#ffffff\"}},\"blocks\":[{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"vertical\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"30px\"}}},{\"type\":\"text\",\"text\":\"<h1 style=\\\"text-align: center\\\">[site:title]</h1>\"},{\"type\":\"text\",\"text\":\"<p style=\\\"text-align: left\\\"><span>Hello [subscriber:firstname | default:there],</span><span></span></p>\\n<p style=\\\"text-align: left\\\"><span></span></p>\\n<p style=\\\"text-align: left\\\"><span>You\'ve received this message because you subscribed to [site:title]. Please confirm your subscription to receive emails from us:&nbsp;</span></p>\"}]}]},{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"horizontal\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"#ffffff\"}},\"blocks\":[{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"vertical\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"23px\"}}},{\"type\":\"button\",\"text\":\"Click here to confirm your subscription\",\"url\":\"[activation_link]\",\"styles\":{\"block\":{\"backgroundColor\":\"#e9e9e9\",\"borderColor\":\"#333333\",\"borderWidth\":\