(76, 0, 'Подтвердите интерес или отпишитесь', '[\"re_engagement\",\"all\"]', '', '{\"content\":{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"vertical\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"horizontal\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"#ffffff\"}},\"blocks\":[{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"vertical\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"30px\"}}},{\"type\":\"image\",\"link\":\"\",\"src\":\"http:\\/\\/localhost:8080\\/wp-content\\/plugins\\/mailpoet\\/assets\\/img\\/blank_templates\\/fake-logo.png\",\"alt\":\"\\u041f\\u043e\\u0434\\u0434\\u0435\\u043b\\u044c\\u043d\\u044b\\u0439 \\u043b\\u043e\\u0433\\u043e\\u0442\\u0438\\u043f\",\"fullWidth\":false,\"width\":\"598px\",\"height\":\"71px\",\"styles\":{\"block\":{\"textAlign\":\"center\"}}},{\"type\":\"text\",\"text\":\"<p style=\\\"text-align: left;\\\">\\u041f\\u0440\\u0438\\u0432\\u0435\\u0442 [subscriber:firstname | default:there]!<\\/p><p style=\\\"text-align: left;\\\"><\\/p>\\n                                  <p style=\\\"text-align: left;\\\"><span>\\u041f\\u0440\\u043e\\u0448\\u043b\\u043e \\u043d\\u0435\\u043c\\u0430\\u043b\\u043e \\u0432\\u0440\\u0435\\u043c\\u0435\\u043d\\u0438 \\u0441 \\u0442\\u0435\\u0445 \\u043f\\u043e\\u0440, \\u043a\\u0430\\u043a \\u0432\\u044b \\u043e\\u0442\\u043a\\u0440\\u044b\\u0432\\u0430\\u043b\\u0438 \\u043d\\u0430\\u0448\\u0438 \\u043f\\u0438\\u0441\\u044c\\u043c\\u0430. \\u0415\\u0441\\u043b\\u0438 \\u0432\\u044b \\u043f\\u0435\\u0440\\u0435\\u0434\\u0443\\u043c\\u0430\\u043b\\u0438 \\u0441 \\u0442\\u0435\\u0445 \\u043f\\u043e\\u0440, \\u043a\\u0430