g\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:22:\"образование\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:9:\"education\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:9:\"wpcredits\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2748\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:846:\"WordPress Campus Connect, первоначально запущенна в октябре 2024 года в качестве пилотной программы, теперь официально признана серией официальных мероприятий благодаря оглушительному успеху. Программа WordPress Campus Connect выходит за рамки традиционной модели семинаров, создавая целостное обучающее сообщество. Она сочетает обучение в кампусе с разнообразными событиями после основного мероприятия, включая встречи, веб-конкурсы, стипендии и возможности волонтерства, и [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:3:\"Yui\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4863:\"\n<p class=\"wp-block-paragraph\">WordPress Campus Connect, <a href=\"https://central.wordcamp.org/news/2024/12/wp-campus-connect-recap-a-journey-of-empowering-students-and-building-community/\" target=\"_blank\" rel=\"noreferrer noopener\">первоначально запущенна в октябре 2024 года в качестве пилотной программы</a>, теперь официально признана серией официальных мероприятий благодаря оглушительному успеху.</p>\n\n\n\n<figure class=\"wp-block-image\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/05/1H4A6596.jpg?resize=1024%2C683&amp;ssl=1\" alt=\"\" class=\"wp-image-18733\" /></figure>\n\n\n\n<figure class=\"wp-block-image\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/05/1H4A8902.jpg?resize=1024%2C683&amp;ssl=1\" alt=\"\" class=\"wp-image-18735\" /></figure>\n\n\n\n<figure class=\"wp-block-image\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/05/image.jpeg?resize=1024%2C682&amp;ssl=1\" alt=\"\" class=\"wp-image-18729\" /><figcaption class=\"wp-element-caption\">фотографии с WordPress Campus Connect, Индия, Аджмер</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\n\n\n<p class=\"wp-block-paragraph\">Программа WordPress Campus Connect выходит за рамки традиционной модели семинаров, создавая целостное обучающее сообщество. Она сочетает обучение в кампусе с разнообразными событиями после основного мероприятия, включая встречи, веб-конкурсы, стипендии и возможности волонтерства, и все это направлено на развитие студентов.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Официальное признание WordPress Campus Connect как серии мероприятий открывает путь к дальнейшему расширению, предоставляя этой серии такую ​​же поддержку и статус, как и WordCamp, но с целью и фокусом, ориентированным на образование студентов. В планы на будущее входит организация крупномасштабных студенческих мероприятий, создание клубов WordPress в кампусах колледжей и содействие наставническим связям для студентов.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Если вы являетесь студентом, заинтересованым в проведении мероприятий WordPress Campus Connect в вашем учебном заведении, или преподавателем желающим стать организатором, или, возможно, организацией желающей проспонсировать проведение Campus Connect в техническом ВУЗе вашего города, то посмотрите следующие страницы для получения большего количества информации об организации и участии:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://ru.wordpress.org/education/campus-connect/\" target=\"_blank\" rel=\"noreferrer noopener\">Об инициативе WordPress Campus Connect</a> (информация, ссылки на регистрацию)</li>\n\n\n\n<li><a href=\"https://ru.wordpress.org/education/student-clubs/\" target=\"_blank\" rel=\"noreferrer noopener\">О студенческих клубах</a></li>\n\n\n\n<li><a href=\"https://ru.wordpress.org/education/credits/\" target=\"_blank\" rel=\"noreferrer noopener\">О программе WP Credits</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/handbook/education/\" target=\"_blank\" rel=\"noreferrer noopener\">Подробное руководство об образовательных программах WordPress</a> (на английском)</li>\n\n\n\n<li><a href=\"https://ru.wordpress.org/files/2025/12/RU-WordPress-Campus-Connect-Pitch-Deck-1.pdf\">Питч-дек</a> (краткая) презентация возможностей WordPress Campus Connect</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Вы также можете задать все интересующие вас вопросы в онлайн-чате <a href=\"https://make.wordpress.org/chat/\" target=\"_blank\" rel=\"noreferrer noopener\">Make WordPress</a> на канале <strong>#campusconnect</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2748\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:63:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:85:\"Прекращение поддержки старых версий WordPress 4.1-4.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://ru.wordpress.org/news/2025/06/dropping-security-updates-for-wordpress-versions-4-1-through-4-6/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 19 Jun 2025 16:30:40 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:22:\"Исправления\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:14:\"Новости\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"Релизы\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2717\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:852:\"Команда безопасности WordPress прекратит предоставлять обновления для версий WordPress 4.1–4.6, начиная с июля 2025г. Официально WordPress предоставляет поддержку только последней версии программного обеспечения. Команда безопасности исторически практикует предоставление исправлений безопасности в качестве любезности для сайтов с более старыми версиями в ожидании, что сайты будут автоматически обновлены. В декабре 2022г была прекращена поддержка безопасности веток 3.7 [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:3:\"Yui\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2235:\"\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/security/\" target=\"_blank\" rel=\"noreferrer noopener\">Команда безопасности</a> WordPress прекратит предоставлять обновления для версий WordPress 4.1–4.6, начиная с июля 2025г.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Официально WordPress предоставляет поддержку только последней версии программного обеспечения. Команда безопасности исторически практикует предоставление исправлений безопасности в качестве любезности для сайтов с более старыми версиями в ожидании, что сайты будут автоматически обновлены.</p>\n\n\n\n<p class=\"wp-block-paragraph\">В <a href=\"https://ru.wordpress.org/news/2022/11/dropping-security-updates-for-wordpress-versions-3-7-through-4-0/\">декабре 2022г была прекращена поддержка безопасности</a> веток 3.7 &#8212; 4.0.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Как всегда владельцам сайтов рекомендуется обновить WordPress, предпочительно до последней версии.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Если у вас возникнут проблемы при переходе к новой версии WordPress, вы можете обратиться на <a href=\"https://ru.wordpress.org/support/\" target=\"_blank\" rel=\"noreferrer noopener\">форумы поддержки</a>. Не забывайте о резервном копировании перед внесением изменений на свой сайт.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Подробности о прекращении поддержки старых версий можно прочитать в <a href=\"https://make.wordpress.org/security/2025/06/18/security-updates-will-cease-for-wordpress-versions-4-1-through-4-6/\">блоге Команды безопасности</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2717\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:52:\"Предупреждение о мошенниках\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:54:\"https://ru.wordpress.org/news/2023/12/scam-alert-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 05 Dec 2023 14:27:02 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:14:\"Новости\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:25:\"Общие вопросы\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2647\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:802:\"В последнее время администраторы сайтов WordPress стали заметно чаще получать письма якобы от WordPress.org или WordPress.com. Примерный текст такого письма: Уважаемый владелец сайтаМы хотим обратить ваше внимание на некоторые важные&#160;изменения в наших правилах&#160;и предписаниях, которые влияют на работу вашего&#160;веб-сайта WordPress.Для обеспечения безопасности и качества обслуживания необходимо принять новые правила. Если вы с ними не согласны [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:3:\"Yui\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5040:\"\n<p class=\"wp-block-paragraph\">В последнее время администраторы сайтов WordPress стали заметно чаще получать письма якобы от WordPress.org или WordPress.com.  Примерный текст такого письма:</p>\n\n\n\n<div class=\"wp-block-group is-layout-constrained wp-block-group-is-layout-constrained\">\n<figure class=\"wp-block-pullquote has-text-align-left has-small-font-size\"><blockquote><p>Уважаемый владелец сайта<br>Мы хотим обратить ваше внимание на некоторые важные&nbsp;<strong>изменения в наших правилах</strong>&nbsp;и предписаниях, которые влияют на работу вашего&nbsp;веб-сайта WordPress.<br>Для обеспечения безопасности и качества обслуживания необходимо принять новые правила. Если вы с ними не согласны и не предпримете необходимых действий,&nbsp;<strong>ваш веб-сайт будет отключен</strong>.<br><br>КНОПКА ДЛЯ ПЕРЕХОДА<br>Пожалуйста, ознакомьтесь с изменениями и примите решение до&nbsp;<strong>12.05.2023</strong>. Мы ценим ваше сотрудничество и готовы помочь вам с любыми вопросами или озабоченностями.<br>Спасибо вам за ваше понимание и оперативные действия!<br><br>Automattic, Inc. — 60 29th St. #343, Сан-Франциско, Калифорния 94110</p></blockquote></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Обращаем ваше внимание, WordPress Foundation, Automattic Inc, Команда безопасности WordPress <strong>не рассылают писем</strong> владельцам сайтов, не просят переходить по ссылкам для принятия каких-либо условий, не просят установить никаких плагинов или совершать иные действия не связанные со штатным обновлением вашего сайта (Консоль-Обновления).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Если вы подписаны на какие-либо рассылки WordPress, убедитесь что исходящий адрес не был подделан:</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://ru.wordpress.org/files/2023/12/email-details-signed-by-wordpressdotorg.png\"><img fetchpriority=\"high\" decoding=\"async\" width=\"1024\" height=\"450\" src=\"https://ru.wordpress.org/files/2023/12/email-details-signed-by-wordpressdotorg.png\" alt=\"\" class=\"wp-image-2650\" srcset=\"https://ru.wordpress.org/files/2023/12/email-details-signed-by-wordpressdotorg.png 1024w, https://ru.wordpress.org/files/2023/12/email-details-signed-by-wordpressdotorg-300x132.png 300w, https://ru.wordpress.org/files/2023/12/email-details-signed-by-wordpressdotorg-768x338.png 768w\" sizes=\"(max-width: 1024px) 100vw, 1024px\" /></a></figure>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">вы можете сделать это просмотрев служебные заголовки сообщения email.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Официальными доменами являются .wordpress.org и .wordpress.net , а также домены третьего уровня, например ru.wordpress.org (обратите внимание что .wordpress.org является концом доменной части адреса (перед слешем <strong>/</strong>) и перед wordpress.org имеется точка, а не какой-то иной символ, например тире).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Также обращайте внимания на письма исходящие якобы от вашего хостинга, вашего регистратора домена и прочее, в случае сомнений обращайтесь в службу поддержки хостинга, регистратора и.т.д. зайдя в личный кабинет в соответствующем месте. Не переходите по ссылкам из писем и не совершайте сомнительных действий о которых вас просят возможные мошенники.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Официальное сообщение от команды безопасности WordPress (на английском): <a href=\"https://wordpress.org/news/2023/12/alert-wordpress-security-team-impersonation-scams/\" target=\"_blank\" rel=\"noreferrer noopener\">https://wordpress.org/news/2023/12/alert-wordpress-security-team-impersonation-scams/</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2647\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:116:\"Ежегодный опрос пользователей и участников разработки WordPress 2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://ru.wordpress.org/news/2023/09/2023-wordpress-survey/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 28 Sep 2023 15:38:43 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:14:\"Новости\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:25:\"Общие вопросы\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2631\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:827:\"Пользователи, создатели сайтов, создатели расширений и участники разработки предоставляют ценные отзывы посредством ежегодного опроса. В прошлом, 2022 году, исследование получило комплексное обновление, впервые за шесть лет. Общее количество вопросов было сокращено до 29 ( ранее около 100), большинство социально-экономических вопросов были удалены, а также введена шкала Лайкерта. Эти обновления были призваны повысить процент заполнения опроса, [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:3:\"Yui\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:12811:\"\n<div class=\"wp-block-media-text is-stacked-on-mobile\"><figure class=\"wp-block-media-text__media\"><img decoding=\"async\" width=\"768\" height=\"342\" src=\"https://ru.wordpress.org/files/2019/11/image-12-1.png\" alt=\"\" class=\"wp-image-2145 size-full\" srcset=\"https://ru.wordpress.org/files/2019/11/image-12-1.png 768w, https://ru.wordpress.org/files/2019/11/image-12-1-300x134.png 300w\" sizes=\"(max-width: 768px) 100vw, 768px\" /></figure><div class=\"wp-block-media-text__content\">\n<p class=\"wp-block-paragraph\">Каждый год сообщество WordPress проводит ежегодный опрос для пользователей и участников сообщества.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-36078703 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-background has-text-align-center wp-element-button\" href=\"https://survey.alchemer.com/s3/7439442/2023-WordPress-Annual-Survey\" style=\"background-color:#0072b9\" target=\"_blank\" rel=\"noreferrer noopener\">Пройти опрос за этот год</a></div>\n</div>\n</div></div>\n\n\n\n<p class=\"wp-block-paragraph\">Пользователи, создатели сайтов, создатели расширений и участники разработки предоставляют ценные отзывы посредством ежегодного опроса. В прошлом, 2022 году, исследование получило комплексное обновление, впервые за шесть лет. Общее количество вопросов было сокращено до 29 ( ранее около 100), большинство социально-экономических вопросов были удалены, а также введена шкала Лайкерта. Эти обновления были призваны повысить процент заполнения опроса, обеспечить более эффективный и структурированный анализ этих данных и позволить опросу лучше всего оценить темы, которые наиболее важны для сообщества WordPress.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Итоги предыдущего опроса за 2022 год</h2>\n\n\n\n<p class=\"wp-block-paragraph\">В опросе 2022 года процент завершения увеличился на 26%, однако количество заполнений сократилось на 56% до примерно 3400, включая около 800 участников разработки. В этом году опрос стартует ранее чем в прошлом, что, надеемся, позволит увеличить его количество участников.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ключевые моменты:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Опрос показывает более широкое использование блоков и нового редактора сайта (по сравнению с классическим редактором), что не должно вызывать удивления, поскольку тема по умолчанию теперь является темой на блоках</li>\n\n\n\n<li>22% респондентов использовали WordPress всего год или меньше. Те, кто участвует в опросе, также становятся немного старше: меньше ответов от тех, кто моложе 40 лет, чем в предыдущие годы.</li>\n\n\n\n<li>Каждый пятый респондент узнал о WordPress от коллеги и примерно такой же процент благодаря поисковой системе.</li>\n\n\n\n<li>В 2022 году пользователи WordPress продолжали изучать WordPress (68%), обучали других WP (48%) и создавали сайты для других (55%).</li>\n\n\n\n<li>Пользователи WordPress выбирают платформу, потому что она с открытым исходным кодом (62%), гибкая (47%), с низким уровнем риска (45%), экономичная (45%) и имеет положительную репутацию (41%).</li>\n\n\n\n<li>57% участников опроса получали новости и обучение непосредственно на WordPress.org. Хотя это основной источник, другие сайты остаются очень важными: поисковые системы (46%), YouTube (40%), другие сообщества WordPress (35%) и социальные сети (30%).</li>\n\n\n\n<li>Подавляющее большинство респондентов не используют регулярно другие платформы CMS, а 21% респондентов не используют ни один из 20 наиболее популярных плагинов WordPress.</li>\n\n\n\n<li>Респонденты продолжают утверждать, что «WordPress не хуже других платформ CMS или даже лучше», с этим согласны 68%. Элементы, которые респонденты считают лучшими аспектами WordPress, включают «простоту использования», «гибкость» и/или «варианты плагинов» — примерно по 30% каждый. Говоря о наиболее разочаровывающих элементах WordPress, каждый пятый ответил: «Ничего», а примерно 30% упомянули трудности с редактированием сайта / Гутенберг.</li>\n\n\n\n<li>Общий опыт участников остается положительным. 64% поделились положительным опытом, а 24% оценили свой опыт как «нейтральный». Авторы также чувствуют себя желанными гостями с таким же процентом (64% согласны и 24% нейтральны).</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Более подробно ознакомиться с результатами можно скачав <a href=\"https://wordpress.org/news/files/2023/05/2022-Annual-Survey-Final.pdf\" data-type=\"link\" data-id=\"https://wordpress.org/news/files/2023/05/2022-Annual-Survey-Final.pdf\" target=\"_blank\" rel=\"noreferrer noopener\">этот файл PDF</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Опрос этого года</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Чтобы ваш опыт работы с WordPress был представлен в результатах опроса 2023 года, примите участие в опросе прямо сейчас</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-36078703 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background has-text-align-center wp-element-button\" href=\"https://survey.alchemer.com/s3/7439442/2023-WordPress-Annual-Survey\" style=\"background-color:#0072b9\" target=\"_blank\" rel=\"noreferrer noopener\">Пройти опрос</a></div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">Вы также можете пройти опрос на других языках, воспользовавшись ссылкой выше и переключившись на другой язык, благодаря усилиям полиглотов WordPress. Опрос будет открыт в течение пяти недель. Результаты будут опубликованы в блоге WordPress News в начале декабря.  </p>\n\n\n\n<p class=\"wp-block-paragraph\">В этом году, как и в прошлом, в опрос были внесены некоторые улучшения в структуру и набор вопросов. Также тестируется новая платформа, предлагающая обновленный интерфейс, расширенную многоязычную поддержку, расширенные инструменты анализа и визуализации результатов и многое другое. Новая платформа также имеет встроенные средства контроля доступа и конфиденциальности, что гарантирует, что опрос будет отвечать разнообразным потребностям сообщества WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Пожалуйста, <strong>помогите распространить информацию об опросе</strong>, поделившись им в своей сети, через Slack или через записи в социальных сетях. Чем больше людей заполнят опрос и поделятся своим опытом работы с WordPress, тем большую пользу принесет проект.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Безопасность и конфиденциальность данных имеют первостепенное значение для проекта WordPress и сообщества. Учитывая это, все данные будут анонимизированы: никакие адреса электронной почты или IP-адреса не будут связаны с опубликованными результатами. Чтобы узнать больше о политике конфиденциальности WordPress.org, ознакомьтесь с <a href=\"https://ru.wordpress.org/about/privacy/\" target=\"_blank\" rel=\"noreferrer noopener\">политикой конфиденциальности.</a></em></p>\n\n\n\n<h2 class=\"wp-block-heading\">Благодарности</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Спасибо <a href=\"https://www.hostinger.com/\">Hostinger</a>, <a href=\"https://cloud.jetpack.com/\">Jetpack</a>, и <a href=\"http://wordpress.com\">WordPress.com</a> за помощь в продвижении опроса среди своих клиентов.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Благодарим следующих участников сообщества WordPress за помощь в проекте ежегодного опроса, включая создание вопросов, стратегию, составление опроса и перевод:<br><a href=\"https://profiles.wordpress.org/adamsilverstein/\">adamsilverstein</a>, <a href=\"https://profiles.wordpress.org/audrasjb/\">adurasjb</a>, <a href=\"https://profiles.wordpress.org/alvarogois/\">alvarogóis</a>, <a href=\"https://profiles.wordpress.org/atachibana/\">atachibana</a>, <a href=\"https://profiles.wordpress.org/bjmcsherry/\">bjmcsherry</a>, <a href=\"https://profiles.wordpress.org/chanthaboune/\">chanthaboune</a>, <a href=\"https://profiles.wordpress.org/dansoschin/\">dansoschin</a>, <a href=\"https://profiles.wordpress.org/eidolonnight/\">eidolonnight</a>, <a href=\"https://profiles.wordpress.org/fierevere/\">fierevere</a>, <a href=\"https://profiles.wordpress.org/fxbenard/\">fxbénard</a>, <a href=\"https://profiles.wordpress.org/hassantafreshi/\">hassantafreshi</a>, <a href=\"https://profiles.wordpress.org/juliagasparyan/\">juliagasparyan</a>, <a href=\"https://profiles.wordpress.org/kittmedia/\">kittmedia</a>, <a href=\"https://profiles.wordpress.org/manudavidos/\">manudavidos</a>, <a href=\"https://profiles.wordpress.org/nao/\">nao</a>, <a href=\"https://profiles.wordpress.org/nilovelez/\">nilovelez</a>, <a href=\"https://profiles.wordpress.org/rmartinezduque/\">rmartinezduque</a>, и <a href=\"https://profiles.wordpress.org/tobifjellner/\">tobifjellner</a>.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-36078703 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background has-text-align-center wp-element-button\" href=\"https://survey.alchemer.com/s3/7439442/2023-WordPress-Annual-Survey\" style=\"background-color:#0072b9\" target=\"_blank\" rel=\"noreferrer noopener\">Пройти опрос</a></div>\n</div>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2631\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"WordPress отмечает 20 лет! Результаты опроса 2022\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://ru.wordpress.org/news/2023/05/20th-anniversary-and-2022-survey/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 18 May 2023 15:47:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:14:\"Новости\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:25:\"Общие вопросы\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2579\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:621:\"27 мая WordPress отмечает свое 20-летие. По всему миру проходит множество праздников и вечеринок, надеюсь, с тортом, потому что все мы знаем, что вечеринка без торта — это просто встреча. Но если вы еще не присоединились к празднованию, у вас еще есть время, чтобы получить свой сувенир на юбилей WordPress, поделиться вашим любимым воспоминанием о [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:3:\"Yui\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:10547:\"\n<h2 class=\"wp-block-heading\">27 мая WordPress отмечает свое 20-летие.</h2>\n\n\n\n<p class=\"wp-block-paragraph\">По всему миру проходит множество праздников и вечеринок, надеюсь, с тортом, потому что все мы знаем, что вечеринка без торта — это просто встреча.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Но если вы еще не присоединились к празднованию, у вас еще есть время, чтобы получить свой сувенир на юбилей WordPress, поделиться вашим любимым воспоминанием о WordCamp, устроить целую вечеринку, если хотите, или поделиться видео для публикации на <a href=\"https://wp20.wordpress.net\">wp20.wordpress.net</a>. </p>\n\n\n\n<p class=\"wp-block-paragraph\">За двадцать лет WordPress прошел долгий путь от форка Cafe Log и на настоящее время обслуживает 82 миллиона веб-сайтов (43% всех сайтов сети по данным W3Techs) и имеет экономический вес экосистемы в размере 597 миллиардов долларов. Но команда WordPress не останавливается на этом и не может просто сказать &#171;хорошая работа, а теперь просто посмотрим, что будет дальше&#187;. </p>\n\n\n\n<p class=\"wp-block-paragraph\">У WordPress большие планы на будущее, многие из которых основаны на совершенствовании нового редактора блоков в WordPress, который направлен на снижение входных барьеров для людей на любом этапе их обучения. <br><br>Присоединиться к празднованию юбилея WordPress онлайн или найти встречу или мероприятие поблизости можно на сайте <a href=\"https://wp20.wordpress.net\">wp20.wordpress.net</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Результаты ежегодного сообщества WordPress за 2022 год</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Каждый год члены сообщества WordPress предоставляют ценные отзывы в рамках ежегодного опроса. На 2022 год опрос получил комплексное обновление, первое за шесть лет. Общее количество вопросов было сокращено с почти 100 до 29, в основном удалены социально-экономические вопросы и введена шкала Лайкерта. Эти обновления были предназначены для увеличения скорости заполнения опроса, обеспечения более эффективного и структурированного анализа этих данных и позиционирования опроса для наилучшего определения тем, которые наиболее важны для сообщества WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Цель состоит в том, чтобы информация, полученная в ходе опроса, помогла информировать об инициативах и направлениях работы WordPress в ближайшем будущем, наряду с другими сигналами, такими как обсуждения в сообществе, блоги <a href=\"https://make.wordpress.org\">Making WordPress</a> и мероприятия.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Основные моменты</h3>\n\n\n\n<p class=\"wp-block-paragraph\">В выпуске опроса 2022 года процент завершения увеличился на 26%, однако количество представленных материалов уменьшилось на 56% до примерно 3400, включая около 800 участников. Для опроса 2023 года реклама будет увеличена, что, мы надеемся, компенсирует снижение числа заявок. Доля анкет заполненных на русском языке составила 7% (237 участников). Мы очень надеемся увидеть больше в опросе за 2023 год!</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Опрос показывает более широкое использование блоков и нового редактора сайта (по сравнению с классическим редактором), что не должно вызывать удивления, поскольку тема по умолчанию теперь основана на блоках.</li>\n\n\n\n<li>22% респондентов используют WordPress только год или меньше. Те, кто отвечает на опрос, также становятся немного старше: меньше ответов от лиц моложе 40 лет, чем в предыдущие годы.</li>\n\n\n\n<li>1 из 5 респондентов узнал о WordPress от коллеги и примерно такой же процент от использования поисковой системы.</li>\n\n\n\n<li>В 2022 году пользователи WordPress продолжали изучать WordPress (68%), обучали других работе с WP (48%) и создавали сайты для других (55%).</li>\n\n\n\n<li>Пользователи выбирают платформу CMS, потому что она с открытым исходным кодом (62%), гибкая (47%), с низким уровнем риска (45%), рентабельна (45%) и имеет положительную репутацию (41%).</li>\n</ul>\n\n\n\n<ul class=\"wp-block-list\">\n<li>57% участников опроса получали новости и обучающие материалы непосредственно с WordPress.org. Хотя это основной источник, другие сайты остаются очень важными: поисковые системы (46%), YouTube (40%), другие сообщества WordPress (35%) и социальные сети (30%).</li>\n\n\n\n<li>Подавляющее большинство респондентов не используют другие платформы CMS, а 21% респондентов не используют ни один из 20 лучших плагинов WordPress.</li>\n\n\n\n<li>Респонденты продолжают заявлять, что «WordPress не хуже или даже лучше других платформ CMS», с чем согласны 68%. Элементы, которые респонденты считают лучшими аспектами WordPress, включают «простоту использования», «гибкость» и/или «варианты плагинов», всего около 30% каждого. На вопрос о наиболее разочаровывающих элементах WordPress 1 из 5 ответил «ничего», а примерно 30% сослались на трудности с редактированием сайта или редактором блоков.</li>\n\n\n\n<li>Общий опыт участников остается положительным, 64% поделились своим положительным опытом, а 24% оценили свой опыт как «нейтральный». </li>\n</ul>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Участники сообщества также чувствуют себя желанными как и ранее (64% согласны и 24% нейтральны).</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Планы на 2023</h3>\n\n\n\n<p class=\"wp-block-paragraph\">В следующей итерации опроса планируется улучшить языковые возможности, а также продолжить уточнение вопросов вариантов ответов. Важно помнить, что заполнение опроса требует времени, поэтому мы хотим убедиться, что членам сообщества задаются вопросы, которые больше всего помогают WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Предварительный план состоит в том, чтобы запустить опрос 2023 года уже в августе. Это создаст возможность собрать больше результатов и, что наиболее важно, их учета в планировании ключевых инициатив и направлений деятельности на 2024 год. Отзывы сообщества жизненно важны для успеха и направления проекта. </p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-36078703 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button has-custom-width wp-block-button__width-50\"><a class=\"wp-block-button__link has-charcoal-0-color has-pale-cyan-blue-background-color has-text-color has-background wp-element-button\" href=\"https://wordpress.org/news/files/2023/05/2022-Annual-Survey-Final.pdf\">Скачать PDF-файл с результатами опроса</a></div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Для подготовки публикации использованы материалы:</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/news/2023/05/episode-55-happy-anniversary-wordpress/\">Episode 55: Happy Anniversary, WordPress!</a><br><a href=\"https://wordpress.org/news/2023/05/2022-annual-survey-results-next-steps/\">2022 Annual Survey Results &amp; Next Steps</a><br></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2579\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"Люди WordPress: Хаува Абашия\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://ru.wordpress.org/news/2023/03/people-of-wordpress-hauwa-abashiya/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 04 Mar 2023 12:56:03 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:18:\"Люди WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:19:\"people-of-wordpress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2569\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:650:\"В этой статье мы рассказываем о Хауве Абашия, менеджере проектов в Нигерии и Великобритании, чье стремление помогать людям и ее профессиональные навыки нашли применение и признание в глобальном сообществе WordPress. Иногда нам везет найти в жизни дело, к которому мы не только готовы присоединиться, но и отстаивать. Чтобы бы это ни было, оно может помочь [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Olga Gleckler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:30677:\"\n<p class=\"wp-block-paragraph\">В этой статье мы рассказываем о Хауве Абашия, менеджере проектов в Нигерии и Великобритании, чье стремление помогать людям и ее профессиональные навыки нашли применение и признание в глобальном сообществе WordPress.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large is-resized\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/02/feature-img-for-hauwa-powp.jpg\" alt=\"Портретная фотография Хаувы \" width=\"680\" height=\"420\" title=\"Портретная фотография Хаувы \" /></figure>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\">Иногда нам везет найти в жизни дело, к которому мы не только готовы присоединиться, но и отстаивать. Чтобы бы это ни было, оно может помочь нам выйти за рамки повседневной рутины и переосмыслить то, что мы знаем. Именно это случилось с Хаувой, она почувствовала, что нашла свое место и смогла по новому посмотреть на свою жизнь и планы. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Для нее поворотной точкой стало открытие WordPress, проекта с открытым исходным кодом.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Обучение разработке и WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\">В 2017 году Хаува, уже опытный и успешный менеджер проектов, осознала, что не испытывает от работы того же восторга, как раньше, и ей откровенно скучно. «Я знала, что мне по-прежнему нравится работать с проектами и заниматься их управлением, но мне нужно было что-то менять», — вспоминает она.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Тогда Хаува записалась на курсы веб-разработки, где освоила HTML, CSS и немного JavaScript. Одной из возможностей курса было изучение WordPress, и она выбрала его. Преподаватель курса посоветовал ей посетить конференцию WordCamp.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Хаува посчитала, что необходимо иметь базовые знания о CMS (системе управления контентом сайта) до того, как приедет на мероприятие, и углубилась в самостоятельное изучение WordPress. Первый WordCamp, который она посетила, проходил в приморском городе Брайтон на южном побережье Англии. Там она встретила людей, которые стали ее друзьями и наставниками на долгие годы.</p>\n\n\n\n<p class=\"wp-block-paragraph\">«Меня вдохновили встречи с людьми из сообщества WordPress. Моя жизнь и мое желание поддерживать сообщества изменились к лучшему благодаря людям, которых я встретила, и я продолжаю благодарна судьбе за знакомство с ними».</p>\n\n\n\n<h2 class=\"wp-block-heading\">Глобальное сообщество WordPress: от Германии до Нигерии</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Открыв для себя сообщество WordPress в Великобритании, Хаува заинтересовалась его реальными масштабами, и услышав, что WordCamp Europe — флагманское мероприятие, собирающее тысячи людей со всего мира, захотела принять участие в его организации и использовать свои навыки управления проектами. Она подала заявку и стала волонтером в трехдневной конференции, которая в 2019 году проходила в столице Германии, Берлине. На этом мероприятии Хаува познакомилась не только с участниками со всего мира, но и открыла для себя активное сообщество WordPress в своей родной Нигерии. После она обнаружила как легко поддерживать связь с друзьями со всего мира через мессенджеры.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">Вдохновившись людьми, которые использовали WordPress для улучшения жизни людей в Нигерии и других частях Африки, Хаува начала изучать, как WordPress и его глобальное сообщество могут помочь улучшить взаимопонимание между культурами и континентами.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/02/hauwa-and-her-mom.jpg\" alt=\"Хаува и ее мать Розалинд на одном из мероприятий в Нигерии.\" title=\"Хаува и ее мать Розалинд на одном из мероприятий в Нигерии\" /></figure>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\">Отец Хаувы, доктор Ауду Квасау Абашия, и ее мать Розалинд Зулай Абашия — известны своей благотворительной деятельностью, в частности оказанием поддержки людям в Кадуне, на севере Нигерии, и Абудже в центре страны. Хаува поясняет: «Моя мама происходит из семьи, которая делится своими навыками для оказания практической помощи. От друзей, с которыми я познакомилась в WordPress, я узнала, что есть части общества, которые придерживаются такой же этики. Я могла бы стать частью этого, внести свою лепту в развитие Нигерии в будущем».</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ее родители основали благотворительный фонд, цель которого — помощь вдовам, сиротам и детям получить доступ к образованию, от финансов до музыки. Он связывает тех, кто нуждается в помощи, и тех, кто может оказать поддержку.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Хаува говорит: «Обучение людей практическим навыкам, которые можно использовать для получения дохода или которыми можно поделиться с семьей и другими людьми в своем районе, очень важно. Подобные проекты помогают развивать и поддерживать общину. Такие навыки, как шитье и кулинария — это не просто возможность одеться и поставить еду на стол, но и обретение независимости и гордости. Они являются примером того, как микроэкономика может развиваться и вдохновлять людей на мечты, воплощающиеся в жизнь. В ходе своей работы и учебы я убедилась, что технологии, используемые сознательно и с пониманием решаемых задач, способны изменить жизнь общин к лучшему. Такие проекты, как WordPress, могут стать частью этой движущей силы благодаря переводу на родной язык и самому программному обеспечению, позволяющему делиться идеями».</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/02/hauwa-in-2022.jpg\" alt=\"Хаува в Нигерии\" title=\"Хаува в Нигерии\" /></figure>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\">Имея опыт управления проектами и работы в сфере информационных технологий, Хаува все больше интересуется тем, как можно использовать свои навыки не только для сплочения сообщества, но и для практического долгосрочного вклада в местную инфраструктуру и внедрения быстро меняющихся технологий.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Она говорит: «Я бы хотела, чтобы некоторые люди, которым помог фонд, основанный моими родителями, могли поделиться своими идеями и достижениями и вдохновлять других. Одним из путей может стать программное обеспечение с открытым исходным кодом, доступное для использования и которое может работать на мобильных телефонах».</p>\n\n\n\n<p class=\"wp-block-paragraph\">«Побыв представителем <a href=\"https://make.wordpress.org/training/\">Training Team</a> (команды обучения), я на собственном опыте убедилась, насколько важно, чтобы пользователи не являющиеся технарями могли использовать программное обеспечение для обмена своими идеями без необходимости становиться разработчиками. Мы все можем помочь людям быть услышанными, и если мы работаем в сфере технологий, мы играем определенную роль в создании и продвижении доступности инструментов для этого».</p>\n\n\n\n<p class=\"wp-block-paragraph\">В списке желаний Хаувы помочь африканским странам получить доступ к программному обеспечению и технологиям на их местных языках. Она говорит: «Это часть самобытности, уважения и признания различных культур, а не ожидание того, что все будет переведено с английского дословно. Это дает возможность пожилым людям пользоваться программным обеспечением или опубликованным контентом».</p>\n\n\n\n<p class=\"wp-block-paragraph\">Хаува выучила хауса (язык, на котором говорят в нескольких африканских странах) и английский одновременно у себя дома в Нигерии. Она, как и ее родители, получила образование в разных местах, училась и работала в разных странах. В 16 лет Хаува занялась информатикой как развлечением, не догадываясь, что в будущем это станет важной частью ее трудовой жизни. </p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/02/hauwa-in-2015.jpg\" alt=\"Хаува в кафе в 2015 году\" title=\"Хаува в кафе в 2015 году\" /></figure>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\">Она собиралась поступить в университет, чтобы изучать финансы и социологию. Когда она пошла прощаться с классом по информатике, учитель спросил, что она собирается делать. Услышав о ее планах, учитель сказал: «Ты не хочешь заниматься этим, ты хочешь заниматься чем-то в области IT». Этот разговор стал поворотным моментом для Хаувы. Она продолжила изучать вычислительные и информационные системы и объектно-ориентированные информационные системы для получения степени магистра в Великобритании.</p>\n\n\n\n<p class=\"wp-block-paragraph\">На втором курсе университета она также работала с технологиями вводом данных и в смежных областях, поскольку была полна решимости узнать как можно больше о различных направлениях. После окончания магистратуры она выбрала работу, которая позволяла ей работать с системами, их поддержкой, управлением проектами, цепочками поставок и закупками. Она является сторонником изучения как можно большего количества смежных дисциплин, чтобы получить широкий набор инструментов для реального понимания того, что нужно клиентам и как помочь им достичь подходящих и своевременных решений. Эти навыки оказались полезными и в последующие годы, что позволило ей найти время для поддержки конференций WordCamp, митапов и Training Team. Она говорит: «Участники проектов с открытым исходным кодом являются представителями самых разных профессиональных и культурных слоев. Участие в проекте — это отличный способ делиться своими навыками и сохранять их актуальным и быть открытым для новых возможностей обучения».</p>\n\n\n\n<p class=\"wp-block-paragraph\">Хаува сохранила любовь к управлению проектами и образованию, она получила квалификации в этой области, включая Prince 2 и PMP. Она остается верна идее непрерывного обучения в своей сегодняшней работе с Agile и другими методологиями и находит взаимосвязь между работой и своим стремлением к просвещению.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/02/hauwa-at-wc-london-2019-2.jpg\" alt=\"Хаува у стойки регистрации на WordCamp London 2019\" title=\"Хаува у стойки регистрации на WordCamp London 2019\" /></figure>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\">Стремясь поддержать и местное сообщество в Великобритании, Хаува присоединилась к London WordPress Meetup, а в 2019 году стала организатором WordCamp London, где она использовала свой опыт в области управления проектами. Во время этих мероприятий она провела множество бесед, призывая других развивать свои навыки в области ИТ и делясь собственным опытом.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Этот интерес к повышению уровня квалификации других людей естественным образом привел ее к дальнейшему участию в работе команд <a href=\"https://make.wordpress.org/\">Make WordPress</a>. Вдохновленная идеей поделиться своими навыками другим участником проекта, она присоединилась к <a href=\"https://make.wordpress.org/training/\">Training Team</a> на Contributor Day во время WordCamp. Эта команда трудится над созданием онлайн платформы — <a href=\"https://learn.wordpress.org/\">Learn</a>, позволяющей людям осваивать программное обеспечение и поддерживать свои знания актуальными, а также научиться развивать сообщество в своем регионе. Хаува считает, что доступность — ключевой фактор, поэтому она посвятила много времени проработке документации для лучшего понимания. Она считает, что это необходимо для того, чтобы действительно предоставить людям доступную информацию и определить, где требуется дополнительная работа. Ее вера в это только укрепилась, когда она присоединилась к <a href=\"https://make.wordpress.org/accessibility/\">Accessibility Team</a> (команде по обеспечению доступности) релиза WordPress 5.6, и она внесла свой вклад в документацию и образовательные материалы.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Хаува посвятила много часов поддержке Training Team в течение нескольких лет, будучи убежденной в том, что правильные ресурсы могут действительно помочь сообществам во всем мире использовать программное обеспечение с открытым исходным кодом. Она также подчеркивает важность того, чтобы материалы должны быть удобными для пользователей и легко переводиться, поскольку проект WordPress имеет глобальный масштаб.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Вклад в программное обеспечение с открытым исходным кодом заряжает энергией</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Благодаря сочетанию волонтерской деятельности в Великобритании и Нигерии, а также поддержке участников по всему миру, Хаува заново открыла в себе стремление помогать людям — планировать и достигать своих целей. Она смогла поделиться своим 15-летним опытом управления проектами в своей волонтерской деятельности и призывает других рассмотреть эту профессию в качестве карьеры.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image aligncenter size-large\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2023/02/Hauwa-WC-Europe-2019.jpg\" alt=\"Хаува на WordCamp Europe 2019\" title=\"Хаува на WordCamp Europe 2019\" /></figure>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\">«Занимаясь волонтерством, вы работаете рядом с людьми. Управление проектами связано с людьми. Это помощь людям в достижении целей. То же самое можно сделать и через волонтерство, и вы можете многому научиться, встречаясь с людьми из разных мест». </p>\n\n\n\n<p class=\"wp-block-paragraph\">«Одним из моих стимулов является использование технологий для решения проблем. Для меня, как руководителя проектов, большая честь помогать людям и организациям определять и достигать цели. Это позволяет им обрести ценность. Это одна из причин, по которой меня потянуло к поиску технологических сообществ и участию в них. Если это то, что движет вами, читающими о моем опыте, то у вас есть широкие возможности поделиться своими навыками. Найдите то, что подходит именно вам, там, где вы сейчас находитесь». </p>\n\n\n\n<p class=\"wp-block-paragraph\">Хаува призывает всех, кто работает в сфере технологий, углубить свое понимание управления проектами и работы с различными командами. «Навыки управления проектами очень важны, в каком бы проекте вы ни работали. Из-за долгих рабочих часов на протяжении многих лет я чувствовала, что потеряла связь с людьми. Я застряла в, казалось, повторяющемся цикле. Благодаря людям, которых я встретила в сообществе WordPress, и использованию моих профессиональных навыков, я вспомнила о своих собственных ценностях и о том, как в качестве менеджера проектов я могу помочь другим достичь новых высот или сделать что-то ценное и существенное, чем другие могут использовать».  </p>\n\n\n\n<p class=\"wp-block-paragraph\">В 2022 году Хаува вернулась к работе на полную ставку в национальных и международных проектах впечатляющих своими масштабами и время ее волонтерской работы в рамках глобальных инициатив по развитию сообществ сократилось, но она продолжает вносить свой вклад в WordPress, сосредоточившись на продвижении образовательных проектов и культурной стороне сообщества.</p>\n\n\n\n<p class=\"wp-block-paragraph\">«Я буду продолжать интересоваться тем, как проекты с открытым исходом, такие как WordPress, работая вместе с другими решениями, может помочь некоммерческим организациям в их развитии. По мне, если существуют технологические решения, то мы все можем сыграть определенную роль в их развитии и изменении ситуации».</p>\n\n\n\n<p class=\"wp-block-paragraph\">«То, как мы помогаем сообществам, не обязательно должно оставаться неизменным на протяжении всего времени. Важно постоянно смотреть на то, что необходимо, и на то, какую пользу это может принести».</p>\n\n\n\n<p class=\"wp-block-paragraph\">«Найдите то, что хотела ли бы воплотить для своего родного соообщества, и, возможно, существуют технологии, которые могут воплотить его. Я рада, что начала свое путешествие».</p>\n\n\n\n<h2 class=\"wp-block-heading\">Поделитесь историями</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Познакомьтесь с другими историями в серии «Люди WordPress», помогите поделиться или с другими и присоединяйтесь к нам, чтобы найти новое применение собственным знаниям и талантам, найти друзей и внести вклад в развитие проекта в глобальном масштабе. Тут находят единомышленников и филологи, и самые отъявленные технари. Make WordPress сейчас насчитывает 21 команду, и вы всегда можете присоединиться к русскоязычному комьюнити в Telegram.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Авторы и редакторы</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Спасибо Хауве Абашия (<a href=\"https://profiles.wordpress.org/azhiyadev/\">@azhiyadev</a>) за ее #ContributorStory.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Спасибо Абе Такор (<a href=\"https://profiles.wordpress.org/webcommsat/\">@webcommsat</a>) за интервью и запись, а также Мехер Бала (<a href=\"https://profiles.wordpress.org/meher/\">@meher</a>), Хлое Брингманн <a href=\"https://profiles.wordpress.org/cbringmann/\" data-type=\"URL\" data-id=\"https://profiles.wordpress.org/cbringmann/\">@cbringmann</a>), Мари Баум (<a href=\"https://profiles.wordpress.org/marybaum/\">@marybaum</a>), Налини Такор (<a href=\"https://profiles.wordpress.org/nalininonstopnewsuk/\">@nalininonstopnewsuk</a>) and Майе Лончар (<a href=\"https://profiles.wordpress.org/majaloncar/\">@majaloncar</a>) за редактуру и работу с фотографиями.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Серия Люди WordPress благодарит Джозефу Хейден (<a href=\"https://profiles.wordpress.org/chanthaboune/\">@chanthaboune</a>) и Тофера ДеРозиа (<a href=\"https://profiles.wordpress.org/topher1kenobe/\">@topher1kenobe</a>) за поддержку проекта.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Перевод на русский: Ольга Глеклер (<a href=\"https://profiles.wordpress.org/oglekler/\">@oglekler</a>)</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:33.33%\">\n<figure class=\"wp-block-image\"><img loading=\"lazy\" decoding=\"async\" width=\"180\" height=\"135\" src=\"https://ru.wordpress.org/files/2021/03/heropress-logo.png\" alt=\"\" class=\"wp-image-2268\" /></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:66.66%\">\n<p class=\"wp-block-paragraph\">Эта статья основана на первоначальной публикации HeroPress.com, инициативе, ориентированной на людей в сообществе WordPress, созданной Тофером ДеРозиа&nbsp;<a href=\"https://profiles.wordpress.org/topher1kenobe/\">@topher1kenobe</a>.</p>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">Читайте эту и другие истории серии «<a href=\"https://wordpress.org/news/category/interviews/\">People of WordPress</a>» (на английском) или «<a href=\"https://ru.wordpress.org/news/category/people-of-wordpress/\">Люди WordPress</a>» (на русском).</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2569\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:49:\"Сообщество WordPress Russia в Telegram\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:132:\"https://ru.wordpress.org/news/2023/02/%d1%81%d0%be%d0%be%d0%b1%d1%89%d0%b5%d1%81%d1%82%d0%b2%d0%be-wordpress-russia-%d0%b2-telegram/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 18 Feb 2023 12:57:18 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:14:\"Новости\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:25:\"Общие вопросы\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2558\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:667:\"В связи с закрытием пространства WordPress Russia в Slack с 21 марта 2023 года, были открыты каналы сообщества в Telegram.Добро пожаловать: https://t.me/ru_wp_org На каналах можно как общаться по поводу WordPress и сообщества, по развитию проекта WordPress (внесению своего вклада в проект), так и просто пообщаться (#random). Обратите внимание!Все темы, связанные с поддержкой WordPress следует по-прежнему [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:3:\"Yui\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2643:\"\n<div class=\"wp-block-group is-layout-constrained wp-block-group-is-layout-constrained\">\n<div class=\"wp-block-media-text alignwide is-stacked-on-mobile\"><figure class=\"wp-block-media-text__media\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"300\" src=\"https://ru.wordpress.org/files/2023/02/wapuushkin-wapuu.png\" alt=\"\" class=\"wp-image-2563 size-full\" srcset=\"https://ru.wordpress.org/files/2023/02/wapuushkin-wapuu.png 300w, https://ru.wordpress.org/files/2023/02/wapuushkin-wapuu-150x150.png 150w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></figure><div class=\"wp-block-media-text__content\">\n<p class=\"wp-block-paragraph\">В связи с <a rel=\"noreferrer noopener\" href=\"https://slack.com/blog/news/access-restricted-russia-embargoed-regions-ukraine\" target=\"_blank\">закрытием пространства</a> WordPress Russia в Slack с 21 марта 2023 года, были открыты каналы сообщества в Telegram.<br>Добро пожаловать: <a rel=\"noreferrer noopener\" href=\"https://t.me/ru_wp_org\" target=\"_blank\">https://t.me/ru_wp_org</a></p>\n</div></div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">На каналах можно как общаться по поводу WordPress и сообщества, по развитию проекта WordPress (<a href=\"https://make.wordpress.org/\">внесению своего вклада в проект</a>), так и просто пообщаться (#random).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Обратите внимание!<br>Все темы, связанные с поддержкой WordPress следует по-прежнему создавать на форуме, сообщество в Telegram (как и ранее в Slack) существует<br>прежде всего для общения на темы, связанные с внесением своего вклада в развитие WordPress любым из доступных способов: разработка ядра, дизайн, переводы, ответы на форумах, документация, публикация плагинов и тем в каталоге, организация мероприятий, улучшение самого портала <a href=\"http://WordPress.org\">WordPress.org</a>, тестирование, маркетинг, CLI и т.д.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Для переводов WordPress, плагинов, тем и прочих связаных проектов существует канал <a href=\"https://t.me/wp_translate\">https://t.me/wp_translate</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2558\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:116:\"Ежегодный опрос пользователей и участников разработки WordPress 2022\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://ru.wordpress.org/news/2022/12/2022-wordpress-survey/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 02 Dec 2022 16:13:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:14:\"Новости\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:25:\"Общие вопросы\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2547\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:715:\"Каждый год сообщество WordPress проводит ежегодный опрос для пользователей и участников сообщества. Ключевые выводы и тенденции, выявляемые в результате этого опроса, часто отражаются в ежегодном обращении State of the Word, публикуются в общедоступных блогах проекта и могут влиять на направление и стратегию проекта WordPress. Проще говоря: этот опрос помогает тем, кто создает WordPress, больше узнать [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:3:\"Yui\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6472:\"\n<div class=\"wp-block-media-text alignwide has-media-on-the-right is-stacked-on-mobile\"><div class=\"wp-block-media-text__content\">\n<p class=\"wp-block-paragraph\" style=\"font-size:18px\">Каждый год сообщество WordPress проводит ежегодный опрос для пользователей и участников сообщества. </p>\n</div><figure class=\"wp-block-media-text__media\"><img loading=\"lazy\" decoding=\"async\" width=\"768\" height=\"342\" src=\"https://ru.wordpress.org/files/2019/11/image-12-1.png\" alt=\"\" class=\"wp-image-2145 size-full\" srcset=\"https://ru.wordpress.org/files/2019/11/image-12-1.png 768w, https://ru.wordpress.org/files/2019/11/image-12-1-300x134.png 300w\" sizes=\"auto, (max-width: 768px) 100vw, 768px\" /></figure></div>\n\n\n\n<p class=\"wp-block-paragraph\">Ключевые выводы и тенденции, выявляемые в результате этого опроса, часто отражаются в ежегодном обращении <a href=\"https://wordpress.org/news/2022/11/state-of-the-word-2022/\" target=\"_blank\" rel=\"noreferrer noopener\">State of the Word</a>, публикуются в общедоступных блогах проекта и могут влиять на направление и стратегию проекта WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Проще говоря: этот опрос помогает тем, кто создает WordPress, больше узнать о том, как и кем используется программное обеспечение. Опрос также помогает руководителям проектов с открытым исходным кодом WordPress больше узнать об опыте наших участников.</p>\n\n\n\n<p class=\"wp-block-paragraph\">В этом году опрос был переработан и стал заметно короче, поэтому ответы на него займут у вас не так много времени.</p>\n\n\n\n<p class=\"wp-block-paragraph\">В этом году мы предлагаем пройти вам этот опрос:</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-36078703 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button is-style-outline is-style-outline--1\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://wordpressdotorg.survey.fm/ru-2022\" target=\"_blank\" rel=\"noreferrer noopener\">На русском</a></div>\n\n\n\n<div class=\"wp-block-button is-style-outline is-style-outline--2\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://wordpressdotorg.survey.fm/en-2022\" target=\"_blank\" rel=\"noreferrer noopener\">In English</a></div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">Как и в прошлом году, предлагаются и другие языки: <a href=\"https://wordpressdotorg.survey.fm/fr-2022\">французский</a>, <a href=\"https://wordpressdotorg.survey.fm/de-2022\">немецкий</a>, <a href=\"https://wordpressdotorg.survey.fm/it-2022\">итальянский</a>, <a href=\"https://wordpressdotorg.survey.fm/jp-2022\">японский</a>, и <a href=\"https://wordpressdotorg.survey.fm/es-2022\">испанский</a>. Это шесть наиболее часто используемых языков, помимо английского, основываясь на количестве загрузок программного обеспечения WordPress. Возможно, в 2023 году будут добавлены и другие.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Сбор данных осуществляется в полном соответствии с <a rel=\"noreferrer noopener\" href=\"https://ru.wordpress.org/about/privacy/\" target=\"_blank\">политикой конфиденциальности WordPress.org</a>: все данные будут анонимизированы и не будут ассоциироваться с IP-адресами и адресами e-mail.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Опрос открыт до конца 2022 года, его результаты будут опубликованы позже в блоге WordPress.org. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Помогите распространить информацию об опросе, поделившись им в социальных сетях или иным способом. Чем больше людей пройдут опрос и поделятся своим опытом работы с WordPress, тем больше пользы получит проект в будущем.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Благодарность</h2>\n\n\n\n<p class=\"wp-block-paragraph\">За помощь в создании, оформлении и переводе на национальные языки опроса, спасибо следующим участникам: <a href=\"https://profiles.wordpress.org/dansoschin/\">dansoschin</a>, <a href=\"https://profiles.wordpress.org/_dorsvenabili/\">_dorsvenabili</a>, <a href=\"https://profiles.wordpress.org/angelasjin/\">angelasjin</a>, <a href=\"https://profiles.wordpress.org/arkangel/\">arkangel</a>, <a href=\"https://profiles.wordpress.org/audrasjb/\">audrasjb</a>, <a href=\"https://profiles.wordpress.org/atachibana/\">atachibana</a>, <a href=\"https://profiles.wordpress.org/bjmcsherry/\">bjmcsherry</a>, <a href=\"https://profiles.wordpress.org/chanthaboune/\">chanthaboune</a>, <a href=\"https://profiles.wordpress.org/eidolonnight/\">eidolonnight</a>, <a href=\"https://profiles.wordpress.org/fernandot/\">fernandot</a>, <a href=\"https://profiles.wordpress.org/fierevere/\">fierevere</a>, <a href=\"https://profiles.wordpress.org/fxbenard/\">fxbenard</a>, <a href=\"https://profiles.wordpress.org/jdy68/\">jdy68</a>, <a href=\"https://profiles.wordpress.org/jpantani/\">jpantani</a>, <a href=\"https://profiles.wordpress.org/laurlittle/\">laurlittle</a>, <a href=\"https://profiles.wordpress.org/nao/\">nao</a>, <a href=\"https://profiles.wordpress.org/nielslange/\">nielslange</a>, <a href=\"https://profiles.wordpress.org/peiraisotta/\">peiraisotta</a>, <a href=\"https://profiles.wordpress.org/piermario/\">piermario</a>, <a href=\"https://profiles.wordpress.org/rmartinezduque/\">rmartinezduque</a>, <a href=\"https://profiles.wordpress.org/santanainniss/\">santanainniss</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2547\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:85:\"Прекращение поддержки старых версий WordPress 3.7-4.0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://ru.wordpress.org/news/2022/11/dropping-security-updates-for-wordpress-versions-3-7-through-4-0/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 30 Nov 2022 09:17:40 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:25:\"Общие вопросы\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:12:\"Релизы\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2544\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:826:\"Команда безопасности WordPress прекратит предоставлять обновления для версий WordPress 3.7–4.0, начиная с 1 декабря 2022 года. Официально WordPress предоставляет поддержку только последней версии программного обеспечения. Команда безопасности исторически практикует предоставление исправлений безопасности в качестве любезности для сайтов с более старыми версиями в ожидании, что сайты будут автоматически обновлены. До сих пор эти исправления включали все [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:3:\"Yui\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2456:\"\n<p class=\"wp-block-paragraph\"><a rel=\"noreferrer noopener\" href=\"https://make.wordpress.org/security/\" target=\"_blank\">Команда безопасности</a> WordPress прекратит предоставлять обновления для версий WordPress 3.7–4.0, начиная с 1 декабря 2022 года.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Официально WordPress предоставляет поддержку только последней версии программного обеспечения. Команда безопасности исторически практикует предоставление исправлений безопасности в качестве любезности для сайтов с более старыми версиями в ожидании, что сайты будут автоматически обновлены.</p>\n\n\n\n<p class=\"wp-block-paragraph\">До сих пор эти исправления включали все версии WordPress, поддерживающие автоматические обновления. Версии WordPress 3.7 – 4.0 достигли <a rel=\"noreferrer noopener\" href=\"https://ru.wordpress.org/about/stats/\" target=\"_blank\">уровней использования менее 1%</a> от общего числа установок, где польза от предоставления этих обновлений перевешивается затраченными усилиями.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Сегодня, 30 ноября 2022, выйдут последние обновления для веток 3.7, 3.8, 3.9 и 4.0, в них единственным изменением станет анонсирование прекращения поддержки безопасности и предложение перейти на более свежую версию WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Если у вас возникнут проблемы при переходе к новой версии WordPress, вы можете обратиться на <a rel=\"noreferrer noopener\" href=\"https://ru.wordpress.org/support/\" target=\"_blank\">форумы поддержки</a>. Не забывайте о резервном копировании перед внесением изменений на свой сайт.</p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2544\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:49:\"Люди WordPress: Михаил Кобзарёв\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"https://ru.wordpress.org/news/2022/08/people-of-wordpress-mikhail-kobzarev/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 31 Aug 2022 09:05:59 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:18:\"Люди WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:19:\"people-of-wordpress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ru.wordpress.org/?p=2526\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:742:\"Мы продолжаем серию интервью с участниками русского сообщества WordPress, объединяющем русскоговорящих разработчиков, переводчиков, пользователей и владельцев сайтов по всему миру.&#160; Сегодня мы беседуем с Михаилом Кобзарёвым, автором плагинов и техноблогером, чье имя и никнейм на слуху у всех, кто интересуется новостями WordPress. — Более 13 лет ты совмещаешь веб-разработку с личным блогом, а последние 5 [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Olga Gleckler\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:36168:\"\n<p class=\"wp-block-paragraph\">Мы продолжаем серию интервью с участниками русского сообщества WordPress, объединяющем русскоговорящих разработчиков, переводчиков, пользователей и владельцев сайтов по всему миру.&nbsp;</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-2.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-2-1024x683.jpg\" alt=\"\" class=\"wp-image-2531\" srcset=\"https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-2-1024x683.jpg 1024w, https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-2-300x200.jpg 300w, https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-2-768x512.jpg 768w, https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-2-1536x1024.jpg 1536w, https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-2-2048x1365.jpg 2048w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\">Сегодня мы беседуем с <a href=\"https://profiles.wordpress.org/mihdan/\">Михаилом Кобзарёвым</a>, автором плагинов и техноблогером, чье имя и никнейм на слуху у всех, кто интересуется новостями WordPress.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><em>— Более 13 лет ты совмещаешь веб-разработку с личным блогом, а последние 5 лет еще и </em></strong><a href=\"https://wp-digest.com/\"><strong><em>WordPress Digest</em></strong></a><strong><em> ведешь. Как удается все совмещать и не разбрасываться, что тебя вдохновляет и чему научился за это время?&nbsp;</em></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Начнем с того, что мой общий стаж в разработке почти 19 лет, за которые я перепробовал все методики управления своим временем и проектами. Плюс после переезда из мегаполиса в деревню я стал работать удаленно задолго до того, как это стало мейнстримом. По этим причинам я выработал для себя определенный график труда и отдыха.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Во-первых, никакой работы по выходным, праздникам и в отпуске — мозги нужно постоянно разгружать, иначе очень просто выгореть, когда ведешь несколько проектов одновременно и держишь огромные массивы данных в голове, постоянно что-то просчитываешь, прикидываешь, прорабатываешь разные варианты.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Во-вторых, на протяжении дня обязательны перерывы, во время которых никаких гаджетов и телевизоров быть не должно — глазам тоже нужен отдых. В это время лучше выйти на улицу, пройтись, поглядеть вдаль и помечтать о будущем ) Тут может помочь любой pomodoro таймер.</p>\n\n\n\n<p class=\"wp-block-paragraph\">В третьих, необходимо соблюдать режим дня (который у меня последнее время немного сбился). Исторически сложилось, что мой рабочий день вот уже много лет начинается в 11 и заканчивается в 19 часов по московскому времени. В Москве это самые удобные часы, чтобы добраться до работы и безболезненно уехать домой, а утром всегда есть время на семью: походы по магазинам или поездка в поликлинику с ребенком.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Свой блог я начал вести еще когда учился в университете на радиотехника в Туле, он задумывался именно как дневник/записная книжка для себя и одногруппников, где я делился своими открытиями в чудесном мире разработки на РНР, верстки под IE6, Netscape 4 и Opera 6.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Я очень много поглощаю информации из интернета за день (в основном через RSS как старый добрый олдфаг), особо интересные заметки кладу в закладки для чтения позже. И есть огромное желание делиться этими знаниями с людьми (я помню то время, когда не было интернета и всю информацию мы получали из книг, журналов и энциклопедий), поэтому с появлением Твиттера я стал постить много контента туда, так как&nbsp;под содержимое моего блога.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Со временем русскоязычный Твиттер стал превращаться в помойку и одновременно с этим появился Телеграм, в котором я был одним из первых бета-тестеров. Мы стали переводить рабочие чаты туда, создавать каналы для своих, так появились сначала закрытые, а потом уже и открытые публично чаты и каналы: WordPress Digest (сюда мы постим новости по WordPress), WordPress Jobs (работа вокруг WordPress), Elementor (чат по конструктору страниц Elementor) и многие другие. Основные можно поглядеть у меня <a href=\"https://www.kobzarev.com/wordpress/wordpress-resources/\">в блоге</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Вдохновляет меня на все эти подвиги моя семья и мои родители, я им искренне благодарен за знания, которые они в меня вложили в детстве и научили самостоятельности, благодаря которой я много лет занимаюсь самообразованием и стараюсь помогать другим. А вот опыт больших компаний (Apple, Microsoft, Tesla) меня не вдохновляет, так как они всего лишь попали в нужное место в нужное время. Каждый должен наступить на свои грабли, ведь человек не учится на чужих ошибках.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><em>— Почему WordPress? Всегда ли сложный проект значит «интересный» для тебя как разработчика?</em></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">За эти 19 лет я набрался огромного опыта почти во всех сферах необъятного веба: фронтенд, бэкенд, seo и даже дизайн, перепробовал кучу языков программирования, прошел десятки курсов и прочитал сотни книг, поработал в нескольких крупных компаниях и мелких веб-студий и могу сказать однозначно: WordPress — сила.</p>\n\n\n\n<p class=\"wp-block-paragraph\">К WordPress я пришел не сразу. Это был долгий тернистый путь. Все начиналось с написания своей CMS в компании Ingate (которая была блочная как текущий Gutenberg и использовала ныне непопулярный XML/XSLT).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Потом была своя CMS в студии Imagos на чистом РНР4 без фреймворков, которую можно до сих пор встретить на некоторых сайтах.</p>\n\n\n\n<p class=\"wp-block-paragraph\">А после переезда из Тулы в Москву я попал в информационное агентство, где мы делали сайты для МИД, дипломатов, РАН, поднимали свои информационные, новостные порталы, здесь мне пригодился опыт написания своих CMS под нужды заказчиков и мы с коллегами запилили не просто новую CMS, а целую платформу, на которой сейчас крутится около 12к сайтов для сельских газет, они им достались совершенно бесплатно.</p>\n\n\n\n<p class=\"wp-block-paragraph\">И тут случился кризис в стране и нам пришлось всем временно уйти на удаленку, так как ЗП платить нам перестали, а на дорогу и покушать в Москве нужно было много денег, плюс съемная квартира и маленький ребенок.</p>\n\n\n\n<p class=\"wp-block-paragraph\">В это время, чтобы прокормить семью, пришлось работать с разными CMS (Joomla, Drupal, ModX) и фреймворками (Zend, Symfony, Laravel, Yii).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Компания не смогла быстро выйти из этого кризиса и мы с бывшими коллегами покинули занимаемые должности и запустили несколько стартапов разной направленности, которые мы сделали на популярном тогда Битрикс.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Работая с Битрикс, я испытал много боли и унижения. В итоге мы уперлись в потолок его кастомизации и решили попробовать WordPress, у меня был небольшой опыт работы с ним в то время. Максимум, что я тогда сделал — развернул свой блог на нем и перенес туда все свои заметки за много лет. Так начался мой путь в WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Следующие несколько лет с каждым днем проектов на WordPress мне попадалось все больше и больше, как простых так и сложных, копился опыт и я начал писать свои <a href=\"https://profiles.wordpress.org/mihdan/#content-plugins\">бесплатные плагины под WordPress</a>, которые я по сей день дополняю и поддерживаю, новый функционал добавляется за счет донов и отдается бесплатно.</p>\n\n\n\n<p class=\"wp-block-paragraph\">И вот уже 10 лет я делаю сайты на WordPress, разрабатываю бэкенд для мобильных приложений на WordPress REST API или использую «безголовый» (headless) WordPress для сайтов на React/Vue.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Это не всегда интересные проекты, но всегда достаточно сложные, высоконагруженные и объемные с большим количеством кастомного кода на бэкенде. Я стараюсь не брать (но в качестве исключения иногда беру) совсем простые проекты и не заниматься доработками чужих, предпочитаю стартапы — там всегда можно найти для себя что-то интересное и ограничивает тебя лишь полет фантазии ))</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><em>— Ты родом из маленького села в Магаданской области и сейчас предпочитаешь сельскую местность мегаполисам. Давно ли ты работаешь удаленно, легко ли это и почему выбрал жизнь вне города?</em></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Родился я в поселке Сеймчан («Солнечная долина» по-эвенски) Магаданской области, после окончания школы поступил в ТулГУ в городе Тула на радиотехника и мечтал ремонтировать телевизоры и видеомагнитофоны, но судьба распорядилась иначе и я открыл для себя бесплатный кабинет интернета в Политехе, который меня заворожил, а после того как я случайно нажал CTRL+U на странице <a href=\"http://ya.ru\">ya.ru</a> и увидел разноцветные строки кода — «поплыл» и не могу остановиться до сих пор.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Несколько лет работал в Туле, потом в Москве, потом по стечению обстоятельств попал в деревню под Тулой и мне тут так стало просто и кайфово, что я больше не стал возвращаться в мегаполис. Тут чистый воздух, свое хозяйство, красота, спокойствие и нет городской суеты и пробок, в которых я проводил по 2-4 часа в сутки, живя в большом городе. И так уже 7 лет я удаленщик, не путайте с фрилансом (работаю официально, фултайм).</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-1-1024x683.jpg\" alt=\"Фотографии Михаила Кобзарева на отдыхе с сыном\" class=\"wp-image-2529\" srcset=\"https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-1-1024x683.jpg 1024w, https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-1-300x200.jpg 300w, https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-1-768x512.jpg 768w, https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-1-1536x1024.jpg 1536w, https://ru.wordpress.org/files/2022/08/Mikhail-Kobzarev-1-2048x1365.jpg 2048w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a><figcaption class=\"wp-element-caption\">Михаил на отдыхе с сыном</figcaption></figure>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\">Но есть и свои минусы: за продуктами, в больницу, стоматологию, кинотеатр приходится ездить в город, но это не является проблемой, когда у тебя есть автомобиль и четкий распорядок дня, когда ты можешь час-два в день отлучиться по личным вопросам.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><em>— Сейчас в профессиональных чатах активно обсуждается тема трудоустройства и возникает ощущение, что работодатели и кандидаты не могут друг друга найти. Ты размещаешь в Дайджесте вакансии и общаешься и с теми, и с другими. Действительно ли существует проблема и что нужно делать, чтобы найти работу или нанять подходящего специалиста?</em></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">К сожалению, эта проблема сейчас как снежный ком. Образовалась она не так давно по понятным причинам, в основном из-за оттока специалистов за границу во всех сферах жизни и не только в IT.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Мы с ребятами-волонтерами на нашем проекте <a href=\"https://wp-digest.com/vacancies/\">WordPress Jobs</a> стараемся помогать обеим сторонам, чтобы компании находили достойных специалистов, а соискатели — работу мечты.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Сейчас не достаточно просто разместить резюме на сайте HH.ru. Многие компании ушли с рынка и сейчас практически некому заниматься обучением джунов (за исключением таких компаний как Сбер, Яндекс, Тинькофф), все хотят минимум мидлов, которых осталось тоже не так много, поэтому необходимо помимо резюме иметь открытый живой GitHub аккаунт, где рекрутеры смогут увидеть ваши скилы. Желательно крутиться в тематических чатах, куда HR-ы тоже часто заглядывают дабы схантить новых кандидатов. Не стоит забывать про личные блоги (с моего блога на меня приходит 30% заказов) и LinkedIn (правда придется заморочиться с VPN).</p>\n\n\n\n<p class=\"wp-block-paragraph\">А для компаний один совет — пишите про себя больше и исключительно правду, сейчас всю информацию очень легко проверить, а если работодателя уличат во лжи — доверия от соискателей ждать не стоит. У нас были случаи, когда мы отказывали в размещении вакансий, так как я стараюсь сам лично проверять каждое объявление, «пробивать» компании по открытым базам, общаться с ними лично. Это долго, но снижает процент мошенничества с обеих сторон.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Мы как раз хотим вынести WordPress Jobs на отдельный домен, доработать его, сделать удобный поиск, интеграцию с биржами типа HH.ru и попытаться давать гарантии как это делают фриланс-биржи, добавить возможность менторинга, обучения, но нужно найти заинтересованных спонсоров и участников проекта, а с этим пока не густо.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><em>— Порталы по поиску работы рекомендуют делать отдельные резюме точно подходящие под названия вакансий и писать сопроводительное письмо индивидуально каждому работодателю, это весьма трудоемко и поиск работы может растянуться на месяца. Существует другой подход, аналогичный «воронке продаж»&nbsp; — откликнуться на 1000 вакансий и рассчитывать, что после прохождения 30 собеседований получишь 2-3 предложения о работе. Из-за этого HR специалисты тонут под грудами резюме и подходящие кандидаты, не указавшие в своем резюме все нужные ключевые слова теряются в этом потоке. Есть ли выход из сложившийся практики?</em></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Оба подхода имеют место быть, в каждом из них есть свои плюсы и минусы.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Первый подход со стороны соискателя позволяет более точечно подстраиваться под вакансии с определенным набором ключевых слов, но на создание такого количества резюме нужно очень много времени и велик шанс ошибиться лишь в одном месте, наплодив ошибку повсеместно, что может негативно сказаться на вас в дальнейшем. Рекрутерам и компаниям здесь проще в поиске соискателя, но не всем нравится копаться в груде одинаковых резюме, где отличается пара абзацев или список скиллов. С их точки зрения это похоже на переспам и плюсов вам особо не добавит. Это больше моё личное мнение и доверять ему на 100% не нужно.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Второй подход я считаю более надежным и проверенным годами, сам им часто пользуюсь. Соискателю достаточно создать резюме на любой площадке или в своём блоге или на GitHub и откликнуться хоть на 100500 вакансий и вы с уверенностью в 99% получите пару-тройку офферов. HR, конечно, закопаются в огромном количестве откликов, но такая у них работа.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Тут самое главное найти золотую середину в обоих подходах и составить детализированное резюме. Постараться указать развернуто должность, на которую вы претендуете, все свои hard и soft skills, опыт работы в хронологическом порядке, занимаемую должность, выполняемые обязанности и ваши достижения в каждой из компаний, где вы когда-либо работали.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Высшее образование в текущих реалиях не является обязательным условием приема на работу, но указать его желательно. Многие компании до сих пор требуют наличие диплома о высшем образовании для отчетности, не более того.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">Обязательно укажите контакты, по которым с вами можно связаться в реальном времени. Если есть какие-то рекомендательные или сопроводительные письма &#8212; тоже добавьте их к вашему резюме.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Не стоит указывать ничего лишнего.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Если вы устраиваетесь не в русскоязычную компанию, то сделайте копию вашего резюме на английском языке.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><em>— Для WordPress существует огромное количество плагинов и тем, создать сайт можно в считанные минуты, и многие разработчики специализируются на «сборке» сайтов и у них даже не возникает необходимости «заглядывать под капот». В результате работодатели не знают с каким стеком технологий разработчик им нужен, а кандидаты претендуют на работу, которая им не подходит. Можно ли кардинально изменить ситуацию?</em></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Работодатель по факту и не должен это знать, это больше задача HR или тех людей с техническими навыками, кто у вас будет проводить в итоге собеседования. К сожалению, уровень знаний HR сейчас тоже оставляет желать лучшего, и очень часто годные специалисты не проходят их отсев, но тут только самим проводить интервью.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ну и стоит справедливо заметить, что существует огромное количество проектов, где технические навыки для соискателя вообще не нужны. Нет необходимости знать PHP, JavaScript, HTML, SQL, чтобы поставить пачку плагинов, потыкать пару кнопок в админке и запустить сайт для проверки какой-то гипотезы или прощупывания ниши. Мы таких специалистов в своём сообществе называем «Модератор админки».</p>\n\n\n\n<p class=\"wp-block-paragraph\">А есть очень сложные, запутанные проекты с кучей логики, микросервисов и высокой нагрузкой, где без технических знаний ты и дня не продержишься.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Поэтому вакансии должен создавать не руководитель и не менеджер проекта, а технически подкованный специалист, ваш будущий коллега, который на пальцах может расписать в резюме, что же вас ждет на будущей работе.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><em>— Опытные разработчики часто находятся в латентном поиске, то есть сидят и ждут, когда работодатель придет и предложит. Это работает? Что делать работодателю, которому нужен специалист на сложный высоконагруженный проект? Есть ли они вообще такие?</em></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Я сам постоянно нахожусь в латентном поиске и жду «работу мечты», где мне будет интересно и за это будут соответствующе платить. Это работает, работало и будет работать. И таких специалистов в режиме ожидания достаточно много, обычно они собираются в сообществах в социальных сетях и прекрасно знают друг друга.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Поэтому, если вам нужно найти реально хорошего профессионала на высоконагруженный проект, то нет ничего лучше, чем «сарафанное радио». Гуру обычно уже где-то работают, но если знакомый коллега предложит что-то более интересное, то, скорее всего, у работодателя появится шанс схантить к себе этого человека. Тут главное внимательно посмотреть соцсети, блоги и GitHub аккаунт, чтобы не попасть на простого «разговорника», которые встречаются в любом сообществе. На словах они гуру, а по факту не далеки от джунов.</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><em>— Что ты посоветуешь тем, кто хочет начать свою карьеру как WordPress-разработчик? Многие курсы предлагают трудоустройство после обучения. Насколько это реально?</em></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Посоветую только одно — не бояться. WordPress не страшный и не монструозный как его обычно описывают поклонники классического ООП и любители фреймворков типа Symfony и Laravel. У него есть EAV (Entity Attribute Value) вместо ORM и EDA (Event Driven Architecture) вместо MVC. Именно из-за этих отличий у многих разработчиков возникает нелюбовь к WordPress — они не понимают архитектуру и не допускают мысли, что почерпнутые в книгах по ООП подходы не являются единственно правильными. Никто не запрещает использовать ООП, PSR.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress уже давно не простенькая CMS для создания бложиков. У нее под капотом более <a href=\"https://codex.wordpress.org/WordPress_APIs\">десятка различных API для разработчика</a>, весь код покрыт юнит-тестами, соответствует стандартам WPCS (WordPress Coding Standards для PHP_CodeSniffer), простой интерфейс для создания CRUD постепенно внедряется так любимое многими разработчиками ООП. На этом движке можно построить проект любой сложности, главное делать это с головой (MVC, headless, CMF).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Не просто так же WordPress <a href=\"https://w3techs.com/technologies/overview/content_management\">уже занял 43%</a> всемирного рынка сайтов в вебе.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Единственное чего пока лично мне не хватает — это удобного интерфейса для работы с кастомными таблицами и поддержки composer для пакетов. Но мы справляемся при помощи WP_List_Table (базовый класс для создания таблиц со списком чего угодно в WordPress. Таблицы поддерживают технологию AJAX. На базе этого класса выводится все виды таблиц в админ-панели WordPress).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Трудоустройство после курсов вполне реально и многие компании именно так и поступают — сами себе выращивают специалистов и пытаются их как-то заинтересовать и замотивировать, чтобы готовые к употреблению разработчики не разбежались (подбирают интересные проекты, благодарят финансово).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Если вы думаете, что на WordPress нельзя заработать более 60.000 рублей в месяц, то вы ошибаетесь, рынок труда просто огромен, количество проектов еще больше и ценником в 300.000 рублей в месяц уже никого не удивишь.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Читайте книги, гуглите Яндексом и почаще посещайте <a href=\"https://wp-kama.ru/\">ВП-Каму</a>. Подписывайтесь на <a href=\"https://t.me/+RArNVwv2tJi2CNFk\">WordPress Digest</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Дерзайте! Всё будет WordPress!</p>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\">Вопросы и работа с изображениями:&nbsp;<a rel=\"noreferrer noopener\" href=\"https://profiles.wordpress.org/oglekler/\" target=\"_blank\">Глеклер Ольга</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"2526\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:35:\"https://ru.wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"13096041\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:11:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Wed, 15 Apr 2026 17:10:28 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Sun, 01 Feb 2026 12:46:15 GMT\";s:4:\"link\";s:61:\"<https://ru.wordpress.org/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}s:5:\"build\";i:1775236851;s:21:\"cache_expiration_time\";i:1776316228;s:23:\"__cache_expiration_time\";i:1776316228;}', 'off');
