ock-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20395\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/DSC04422.jpg?resize=1024%2C576&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20396\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/DSC08957.jpg?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20397\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/DSC08902.jpg?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20399\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/DSCF0500-1.jpg?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20400\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/IMG_9404.jpg?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20401\" height=\"1024\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/IMG_0682.jpg?resize=768%2C1024&#038;ssl=1\" width=\"768\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20398\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/DSC08899.jpg?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20389\" height=\"536\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/FamilyPhoto-Framed.png?resize=1024%2C536&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n</figure>\n\n\n\n<h2 class=\"wp-block-heading\">Conference Sessions Take Shape</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Across the conference days, WordCamp Asia 2026 covered a wide range of topics, from technical development and hands-on workshops to business strategy and the open web. Sessions took place across the Foundation, Growth, and Enterprise tracks, with workshops running alongside the main program.</p>\n\n\n\n<p class=\"wp-block-paragraph\">One of the opening sessions was James LePage’s <em>WordPress and AI</em>, which introduced a theme that appeared throughout the conference: how WordPress is responding to changes in AI, publishing, and developer workflows. That topic continued in later sessions focused on AI-driven development, autonomous testing, plugin maintenance, and automation.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Later that morning, a fireside chat with Mary Hubbard and Shilpa Shah shifted the focus toward trust, security, and the longer-term questions shaping open source publishing. Coming early in the program, the conversation gave the conference an important center of gravity, pairing technical change with questions of stewardship, resilience, and what people needed from WordPress as the web continued to evolve. Rather than pulling away from the event’s technical momentum, it deepened it, bringing a human perspective to the pace of change and reminding the audience that progress in open source is not only about what gets built, but about how communities guide, challenge, and sustain that work over time.<br /></p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">From there, the conference widened into a program that balanced developer-focused talks with sessions on the <a href=\"https://asia.wordcamp.org/2026/session/from-static-to-dynamic-mastering-the-interactivity-api/\">Interactivity API</a>, the <a href=\"https://asia.wordcamp.org/2026/session/parsing-html-without-pain-real-world-use-cases-for-wordpress-html-api/\">HTML API</a>, <a href=\"https://asia.wordcamp.org/2026/session/building-better-wordpress-experiences-with-ai-driven-development-workflows/\">AI-driven development workflows</a>, <a href=\"https://asia.wordcamp.org/2026/session/education-initiatives-in-the-wordpress-ecosystem/\">education initiatives</a>, <a href=\"https://asia.wordcamp.org/2026/session/from-reactive-to-proactive-modern-observability-for-wordpress/\">observability</a>, <a href=\"https://asia.wordcamp.org/2026/session/ten-times-the-value-why-automation-is-worth-the-investment-in-open-source/\">automation</a>, and <a href=\"https://asia.wordcamp.org/2026/session/wordpress-for-startup-founders-the-advantages-are-real-and-so-are-the-traps/\">startup strategy</a>. On the final day, those threads continued through talks on <a href=\"https://asia.wordcamp.org/2026/session/the-invisible-gotchas-of-wp-translation/\">WP translation</a>, <a href=\"https://asia.wordcamp.org/2026/session/building-wordpress-communities-the-ugandan-story/\">community building</a>, <a href=\"https://asia.wordcamp.org/2026/session/wordpress-playground-ai-building-autonomous-testing-pipelines/\">WordPress Playground</a>, <a href=\"https://asia.wordcamp.org/2026/session/wordpress-org-analytics-data-engineering-starter-project/\">data engineering</a>, <a href=\"https://asia.wordcamp.org/2026/session/enterprise-wordpress-isnt-just-bigger-wordpress-lessons-from-the-field/\">enterprise WordPress</a>, and <a href=\"https://asia.wordcamp.org/2026/session/panel-journalism-on-the-open-web/\">journalism on the open web</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Together, the two conference days made clear that WordCamp Asia 2026 was designed not for one kind of attendee, but for many. Developers, founders, marketers, contributors, organizers, and people finding their place in WordPress for the first time all found something that spoke directly to their work and interests. The breadth of the program was striking, but so was the feeling that these conversations mattered now.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Building What Comes Next</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordCamp Asia 2026 closed with reflections from Mary Hubbard, following an opening announcement from Chenda Ngak that WordCamp India will join the calendar in 2027 as the fourth flagship WordPress event.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Mary’s remarks tied together several threads that had already surfaced throughout the event: India’s long-standing role in the WordPress project, the growth of programs like Campus Connect and WordPress Credits, the energy of YouthCamp, and the significance of WordPress 7.0. One of the clearest ideas in the session was that WordPress is entering a new phase shaped by real-time collaboration, AI infrastructure, and global contributor growth. That framing gave the closing session a strong sense of direction without losing sight of the community work that made it possible.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">The session then shifted into a panel discussion about the current state of WordPress and where the project is headed next. Peter Wilson and Sergey Biryukov joined Hubbard on stage, while audience questions brought the conversation back to many of the themes that had shaped the event across all three days. Even from afar, Ma.tt Mullenweg remained part of the discussion, following along remotely and sending written responses during the live Q&amp;A.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Those questions touched on contributor growth, AI, plugins, local communities, product direction, and the long-term health of the open web. What stood out was how often the answers returned to the same core idea: WordPress continues to grow through open discussion, shared responsibility, and the people who keep showing up to build it together.</p>\n\n\n\n<h2 class=\"wp-block-heading\">A Lasting Momentum</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Over three days in Mumbai, WordCamp Asia 2026 brought together contribution, learning, and community. From Contributor Day through the closing keynote, the event balanced hands-on work with bigger conversations about publishing, technology, education, and the open web.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The event also created space for many kinds of participation. Some attendees contributed to Core, Training, Polyglots, Photos, and other teams. Others came for the conference program, workshops, or the chance to reconnect with collaborators and meet new people. Across session rooms, tea breaks, shared meals, sponsor hall conversations, and the after party, the community side of the event remained just as important as the formal program.</p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped has-black-background-color has-background wp-block-gallery-2 is-layout-flex wp-block-gallery-is-layout-flex\" style=\"border-width: 20px; border-radius: 2px;\">\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20408\" height=\"575\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/IMG_9030.jpg?resize=1024%2C575&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20410\" height=\"575\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/Copy-of-IMG_0065.jpg?resize=1024%2C575&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20409\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/shilpa-mary.jpg?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20416\" height=\"769\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/WordPress-AI-6-2.jpg?resize=1024%2C769&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20413\" height=\"575\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/IMG_9040.jpg?resize=1024%2C575&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20412\" height=\"769\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/WordPress-AI-1-21.jpg?resize=1024%2C769&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20417\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/IMG_9803.jpg?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20415\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/DSCF0499.jpg?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20414\" height=\"575\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/IMG_9045.jpg?resize=1024%2C575&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-20407\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/IMG_9867-1-scaled-2.webp?resize=1024%2C683&#038;ssl=1\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n</figure>\n\n\n\n<p class=\"wp-block-paragraph\">Thank you to the organizers, volunteers, speakers, sponsors, attendees, and everyone who joined online. WordCamp Asia 2026 was a reminder that WordPress continues to grow through the people who show up to contribute and build together.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There is still more to look forward to this year. The community will gather again at <a href=\"https://europe.wordcamp.org/2026/\">WordCamp Europe 2026 in Kraków, Poland</a> from June 4–6, followed by <a href=\"https://us.wordcamp.org/2026/\">WordCamp US 2026 in Phoenix, Arizona</a> from August 16–19.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 11 Apr 2026 18:21:14 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"Open Channels FM: How AI Is Reshaping Release Communication in Open Source Projects\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2551276\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:90:\"https://openchannels.fm/how-ai-is-reshaping-release-communication-in-open-source-projects/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:184:\"AI is revolutionizing release communication for open source projects by automating updates, enhancing clarity, and maintaining human oversight, ensuring effective information delivery.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 10 Apr 2026 08:47:07 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"Gary: Claudaborative Editing 0.4: Twice the fun!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:25:\"https://pento.net/?p=5741\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://pento.net/2026/04/10/claudaborative-editing-0-4-twice-the-fun/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:5369:\"<p class=\"wp-block-paragraph\">I&#8217;ve been taking an iterative approach to building Claudaborative Editing: build something to prove that the underlying concept works, then evolve on top of that. The first two iterations were answering a question I had: <a href=\"https://pento.net/2026/03/28/claudaborative-editing-0-2-now-with-500-more-collaboration/\">can an LLM genuinely improve the writing process</a>? Along the way, I found a more important question: <a href=\"https://pento.net/2026/04/07/the-human-in-the-loop/\">can it be done without contributing to the masses of generated slop we see</a>? </p>\n\n\n\n<p class=\"wp-block-paragraph\">Having seen the underlying idea working, I needed to answer the next question: can it be brought into the actual writing environment? Can it be useful, but keep out of the way?</p>\n\n\n\n<p class=\"wp-block-paragraph\">Can you talk to an LLM from within WordPress, and have it talk back? I think I&#8217;m onto something, and it&#8217;s <a href=\"https://core.trac.wordpress.org/ticket/60000\">alot</a> of fun.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Coming to a WordPress Near You</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Naturally, the next step was to build a WordPress plugin that provided a straightforward interface to the LLM backend. You still install the tool to run with your local copy of Claude Code, but once it&#8217;s running, you can do everything directly from the block editor. The plugin is waiting to be approved for the WordPress.org plugin directory, but you can <a href=\"https://github.com/pento/claudaborative-editing/releases\">download it directly from the GitHub repo now</a>.</p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-4 is-cropped wp-block-gallery-1 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><img alt=\"A screenshot of the Collaborative Editing Menu. It shows 5 options: Compose, Proofread, Review, Edit, and Translate.\" class=\"wp-image-5779\" height=\"682\" src=\"https://pento.net/wp-content/uploads/2026/04/menu.png\" width=\"640\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"A screenshot of the Edit box, where a user can have the LLM make broad changes to their post.\" class=\"wp-image-5778\" height=\"865\" src=\"https://pento.net/wp-content/uploads/2026/04/edit-1024x865.png\" width=\"1024\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"A screenshot of the Translate box, where the user can have the LLM translate their post into other languages. Because this is a freeform field, they\'re not limited to the normal options: they can also translate into weird languages, like &quot;pirate&quot;, or &quot;emoji&quot;.\" class=\"wp-image-5777\" height=\"838\" src=\"https://pento.net/wp-content/uploads/2026/04/translate-1024x838.png\" width=\"1024\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"A screenshot of the pre-publish panel, showing the featured image, a suggested excerpt, and suggestions for new and existing tags and categories to use.\" class=\"wp-image-5794\" height=\"1024\" src=\"https://pento.net/wp-content/uploads/2026/04/pre-publish-419x1024.png\" width=\"419\" /></figure>\n</figure>\n\n\n\n<p class=\"wp-block-paragraph\">Tools are easily accessible when you need them, but otherwise stay out of your way. You choose how much input you want the LLM to have in your writing: it can fix things up for you, or you can ask it to just leave notes and you&#8217;ll decide how you want to proceed. Personally, I prefer to do the work myself, but everyone can choose their level of comfort.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That said, one of the things I often forget to do when writing a post is to tag it properly. If I do remember, I&#8217;m never sure what to tag it with. By the time I get to publishing, I&#8217;m impatient just to get it out in the world! So, now there&#8217;s a button that&#8217;ll give suggestions right before publishing, letting you pick and choose which suggestions to use, and what to drop.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Planning is a Conversation</h2>\n\n\n\n<p class=\"wp-block-paragraph\">I always start Claude Code in planning mode, and I wanted that for posts, too. That&#8217;s where I started this post, and I can absolutely see myself using this every time I need to write a post. Not to do the writing for me, but to help me organise my thoughts. I opened the Compose mode in the sidebar, I had it summarise the changes that I&#8217;ve made in the last 2 weeks, and present a few options for how to collate them. Some I kept, some I dropped.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In a lot of ways, it&#8217;s more like a very advanced <a href=\"https://en.wikipedia.org/wiki/ELIZA\">ELIZA</a>, though rather than just reflecting your words back, it reflects your ideas back in a more structured form.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What&#8217;s next</h2>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;ll be honest, I&#8217;m really happy with how this has turned out so far! I&#8217;d love to hear your feedback as you use it. What would you like to see here? I&#8217;ve already noted down a bunch of ideas that came up just while I was writing this post, so there are definitely more things to come!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Go ahead and give it a shot now:</p>\n\n\n\n<p class=\"wp-block-paragraph\"><code>npx claudaborative-editing start</code></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 10 Apr 2026 05:40:37 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Gary\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:10;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:87:\"Open Channels FM: How Hosting Companies Empower Agencies Through Effective Partnerships\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2552187\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:94:\"https://openchannels.fm/how-hosting-companies-empower-agencies-through-effective-partnerships/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:147:\"In this episode, Adam Weeks and Carrie Smaha discuss agency partner programs, emphasizing ongoing commissions, risk management, and building trust.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Apr 2026 10:33:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:11;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"Greg Ziółkowski: Research: Architecting Tools for AI Agents at Scale\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"https://gziolo.pl/?p=14544\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://gziolo.pl/2026/04/09/research-architecting-tools-for-ai-agents-at-scale/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:420:\"Loading all available tools into an LLM&#8217;s context simultaneously is one of the most consequential architectural mistakes teams make when building AI integrations. The solution isn&#8217;t bigger context windows, and it&#8217;s progressive tool exposure: dynamically presenting only the tools relevant to each interaction. This post surveys the major patterns for doing so, drawn from production servers, [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Apr 2026 05:04:03 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Greg Ziółkowski\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:12;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"Weston Ruter: Adding an MCP Server to the WordPress Core Development Environment\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://weston.ruter.net/?p=39124\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://weston.ruter.net/2026/04/08/adding-an-mcp-server-to-the-wordpress-core-development-environment/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:13938:\"<p class=\"wp-block-paragraph\">I wanted to hook up Claude Code to be able to interact with my local <a href=\"https://github.com/WordPress/wordpress-develop\">wordpress-develop</a> core development environment via MCP (Model Context Protocol). I couldn&#8217;t find documentation specifically for doing this, so I&#8217;m sharing how I did it here.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Assuming you have <a href=\"https://github.com/WordPress/wordpress-develop#getting-started\">set up the environment</a> (with Docker) and started it via <code>npm run env:start</code>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">1. Install &amp; Activate the MCP Adapter plugin</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The MCP adapter is not currently available as a plugin to install from the plugin directory. You instead have to obtain it from GitHub and <a href=\"https://github.com/WordPress/mcp-adapter#installation\">install</a> it from the command line. I <a href=\"https://github.com/WordPress/mcp-adapter#as-a-plugin-alternative-method\">installed it as a plugin</a> instead of as a Composer package:</p>\n\n\n<pre class=\"wp-block-code\"><span><code class=\"hljs language-shell\">cd src/wp-content/plugins\ngit clone https://github.com/WordPress/mcp-adapter\ncd mcp-adapter\ncomposer install</code></span></pre>\n\n\n<p class=\"wp-block-paragraph\">Next,  activate the plugin. Naturally, you can also just activate the “MCP Adapter” plugin from the WP admin. You can also activate it via WP-CLI (but from the project root working directory, since you can&#8217;t run this command from inside of the <code>mcp-adapter</code> directory:</p>\n\n\n<pre class=\"wp-block-code\"><span><code class=\"hljs language-shell\">npm run env:cli -- plugin activate mcp-adapter</code></span></pre>\n\n\n<h2 class=\"wp-block-heading\">2. Register the MCP server with Claude</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Here&#8217;s the command I used to register the <code>wordpress-develop</code> MCP server with Claude:</p>\n\n\n<pre class=\"wp-block-code\"><span><code class=\"hljs language-shell shcb-wrap-lines\">claude mcp add-json wordpress-develop --scope user \'{\"command\":\"npm\", \"args\":&#91;\"--prefix\", \"~/repos/wordpress-develop/\", \"run\", \"env:cli\", \"--\", \"mcp-adapter\", \"serve\", \"--server=mcp-adapter-default-server\", \"--user=admin\"]}\'</code></span></pre>\n\n\n<p class=\"wp-block-paragraph\">Here&#8217;s the JSON with formatting:</p>\n\n\n<pre class=\"wp-block-code\"><span><code class=\"hljs language-json\">{\n	<span class=\"hljs-attr\">\"command\"</span>: <span class=\"hljs-string\">\"npm\"</span>,\n	<span class=\"hljs-attr\">\"args\"</span>: &#91;\n		<span class=\"hljs-string\">\"--prefix\"</span>,\n		<span class=\"hljs-string\">\"~/repos/wordpress-develop/\"</span>,\n		<span class=\"hljs-string\">\"run\"</span>,\n		<span class=\"hljs-string\">\"env:cli\"</span>,\n		<span class=\"hljs-string\">\"--\"</span>,\n		<span class=\"hljs-string\">\"mcp-adapter\"</span>,\n		<span class=\"hljs-string\">\"serve\"</span>,\n		<span class=\"hljs-string\">\"--server=mcp-adapter-default-server\"</span>,\n		<span class=\"hljs-string\">\"--user=admin\"</span>\n	]\n}</code></span></pre>\n\n\n<p class=\"wp-block-paragraph\">You may want to remove <code>--scope user</code> if you just want to register the MCP server for the one project. I tend to re-use the same WP environment for multiple projects (core and plugins), so I think it may make it easier for me to install at the user level instead.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You will also need to change the <code>--prefix</code> arg&#8217;s <code>~/repos/wordpress-develop/</code> value to correspond to where the repo is actually cloned on your system. I include this arg here so that when I start <code>claude</code> inside of a plugin project (e.g. inside <code>src/wp-content/plugins/performance</code>), it is able to successfully run the <code>npm</code> command in the <code>package.json</code> in the ancestor directory. You can remove this <code>--prefix</code> arg if this is not relevant to you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Change the user from <code>admin</code> according to your needs.</p>\n\n\n\n<h2 class=\"wp-block-heading\">3. Expose all abilities to MCP</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Registered abilities are not exposed to MCP by default. This is a safety measure so that AI agents have to be explicitly allowed to perform potentially sensitive actions. So without any plugins active other than the MCP Adapter, prompting Claude with “discover abilities” results in:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">No abilities found. The MCP server connection may be unstable. Try reconnecting again with <code>/mcp</code>.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">However, since this is a local development environment, there is no concern about this (for me at least). To opt in all abilities to be exposed to MCP by default, you can use the following plugin code:</p>\n\n\n<pre class=\"wp-block-code\"><span><code class=\"hljs language-php\">add_filter(\n	<span class=\"hljs-string\">\'wp_register_ability_args\'</span>,\n	<span class=\"hljs-keyword\">static</span> <span class=\"hljs-function\"><span class=\"hljs-keyword\">function</span> <span class=\"hljs-params\">( array $args, string $ability_id )</span>: <span class=\"hljs-title\">array</span> </span>{\n		<span class=\"hljs-keyword\">if</span> (\n			<span class=\"hljs-comment\">// Prevent exposing abilities in MCP except on a local dev environment.</span>\n			wp_get_environment_type() === <span class=\"hljs-string\">\'local\'</span>\n			&amp;&amp;\n			<span class=\"hljs-comment\">// Omit abilities which the MCP Adapter already makes available itself.</span>\n			! str_starts_with( $ability_id, <span class=\"hljs-string\">\'mcp-adapter/\'</span> )\n		) {\n			$args&#91;<span class=\"hljs-string\">\'meta\'</span>]&#91;<span class=\"hljs-string\">\'mcp\'</span>]&#91;<span class=\"hljs-string\">\'public\'</span>] = <span class=\"hljs-keyword\">true</span>;\n		}\n		<span class=\"hljs-keyword\">return</span> $args;\n	},\n	<span class=\"hljs-number\">10</span>,\n	<span class=\"hljs-number\">2</span>\n);</code></span></pre>\n\n\n<p class=\"wp-block-paragraph\">This is also available in a <a href=\"https://gist.github.com/westonruter/3a37d35ef66cdd58315a7c1347d92560\">gist</a> to facilitate installation via <a href=\"https://git-updater.com/\">Git Updater</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Note: This filter does not currently apply if your ability is registered by extending <code>Abstract_Ability</code> in the AI plugin.</p>\n\n\n\n<p class=\"wp-block-paragraph\">At this point, I can now open Claude (or re-connect to the MCP server) and see that it is able to see all (er, most) abilities that are registered on my wordpress-develop env with the same prompt “discover abilities”:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\"><strong>3 WordPress abilities</strong> available:</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>core/get-environment-info</strong> — Returns runtime context (PHP, database, WordPress version) with the ability name.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>core/get-site-info</strong> — Returns site information (all fields or filtered subset)</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>core/get-user-info</strong> — Returns current user profile details</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">When I prompt “what&#8217;s the environment info?” it executes the <code>core/get-environment-info</code> ability via MCP and prints out:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<ul class=\"wp-block-list\">\n<li><strong>Environment</strong>: local</li>\n\n\n\n<li><strong>PHP Version</strong>: 8.3.26</li>\n\n\n\n<li><strong>Database Server</strong>: 8.4.8 (MySQL)</li>\n\n\n\n<li><strong>WordPress Version</strong>: 7.1-alpha-62161-src</li>\n</ul>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">Now the environment just needs more abilities! I&#8217;ve filed a Performance Lab <a href=\"https://github.com/WordPress/performance/issues/2441\">issue</a> for us at the Core Performance table to work on adding abilities during <a href=\"https://asia.wordcamp.org/2026/contributor-day/\">Contributor Day</a> at <a href=\"https://asia.wordcamp.org/2026/\">WordCamp Asia</a> tomorrow.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-medium-font-size wp-block-paragraph\">Where I&#8217;ve shared this:</p>\n\n\n\n<ul class=\"wp-block-social-links is-layout-flex wp-block-social-links-is-layout-flex\"><li class=\"wp-social-link wp-social-link-linkedin  wp-block-social-link\"><a class=\"wp-block-social-link-anchor\" href=\"https://www.linkedin.com/posts/westonruter_adding-an-mcp-server-to-the-wordpress-core-share-7447717681786617856-Fo0y?utm_source=share&#038;utm_medium=member_desktop&#038;rcm=ACoAAACIeJ0BUsdEu-G5aiGg1JkXrMQ-C6tbCsI\"><svg height=\"24\" version=\"1.1\" viewBox=\"0 0 24 24\" width=\"24\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M19.7,3H4.3C3.582,3,3,3.582,3,4.3v15.4C3,20.418,3.582,21,4.3,21h15.4c0.718,0,1.3-0.582,1.3-1.3V4.3 C21,3.582,20.418,3,19.7,3z M8.339,18.338H5.667v-8.59h2.672V18.338z M7.004,8.574c-0.857,0-1.549-0.694-1.549-1.548 c0-0.855,0.691-1.548,1.549-1.548c0.854,0,1.547,0.694,1.547,1.548C8.551,7.881,7.858,8.574,7.004,8.574z M18.339,18.338h-2.669 v-4.177c0-0.996-0.017-2.278-1.387-2.278c-1.389,0-1.601,1.086-1.601,2.206v4.249h-2.667v-8.59h2.559v1.174h0.037 c0.356-0.675,1.227-1.387,2.526-1.387c2.703,0,3.203,1.779,3.203,4.092V18.338z\"></path></svg><span class=\"wp-block-social-link-label screen-reader-text\">LinkedIn</span></a></li>\n\n<li class=\"wp-social-link wp-social-link-twitter  wp-block-social-link\"><a class=\"wp-block-social-link-anchor\" href=\"https://x.com/westonruter/status/2041952919378129271\"><svg height=\"24\" version=\"1.1\" viewBox=\"0 0 24 24\" width=\"24\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M22.23,5.924c-0.736,0.326-1.527,0.547-2.357,0.646c0.847-0.508,1.498-1.312,1.804-2.27 c-0.793,0.47-1.671,0.812-2.606,0.996C18.324,4.498,17.257,4,16.077,4c-2.266,0-4.103,1.837-4.103,4.103 c0,0.322,0.036,0.635,0.106,0.935C8.67,8.867,5.647,7.234,3.623,4.751C3.27,5.357,3.067,6.062,3.067,6.814 c0,1.424,0.724,2.679,1.825,3.415c-0.673-0.021-1.305-0.206-1.859-0.513c0,0.017,0,0.034,0,0.052c0,1.988,1.414,3.647,3.292,4.023 c-0.344,0.094-0.707,0.144-1.081,0.144c-0.264,0-0.521-0.026-0.772-0.074c0.522,1.63,2.038,2.816,3.833,2.85 c-1.404,1.1-3.174,1.756-5.096,1.756c-0.331,0-0.658-0.019-0.979-0.057c1.816,1.164,3.973,1.843,6.29,1.843 c7.547,0,11.675-6.252,11.675-11.675c0-0.178-0.004-0.355-0.012-0.531C20.985,7.47,21.68,6.747,22.23,5.924z\"></path></svg><span class=\"wp-block-social-link-label screen-reader-text\">Twitter</span></a></li>\n\n<li class=\"wp-social-link wp-social-link-bluesky  wp-block-social-link\"><a class=\"wp-block-social-link-anchor\" href=\"https://bsky.app/profile/weston.ruter.net/post/3miyxsxvnek2y\"><svg height=\"24\" version=\"1.1\" viewBox=\"0 0 24 24\" width=\"24\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M6.3,4.2c2.3,1.7,4.8,5.3,5.7,7.2.9-1.9,3.4-5.4,5.7-7.2,1.7-1.3,4.3-2.2,4.3.9s-.4,5.2-.6,5.9c-.7,2.6-3.3,3.2-5.6,2.8,4,.7,5.1,3,2.9,5.3-5,5.2-6.7-2.8-6.7-2.8,0,0-1.7,8-6.7,2.8-2.2-2.3-1.2-4.6,2.9-5.3-2.3.4-4.9-.3-5.6-2.8-.2-.7-.6-5.3-.6-5.9,0-3.1,2.7-2.1,4.3-.9h0Z\"></path></svg><span class=\"wp-block-social-link-label screen-reader-text\">Bluesky</span></a></li>\n\n<li class=\"wp-social-link wp-social-link-threads  wp-block-social-link\"><a class=\"wp-block-social-link-anchor\" href=\"https://www.threads.com/@westonruter/post/DW4atcEDsCO?xmt=AQF09yVgY9426bf4GJZXdKIDdfPxO-IOSdR_WbrxXdA6Ew\"><svg height=\"24\" version=\"1.1\" viewBox=\"0 0 24 24\" wid